'use client';
// 
// import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, MapPin, Clock } from 'lucide-react';
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isSameDay, addMonths, subMonths, isToday } from 'date-fns';
import Link from 'next/link';

export default function CalendarPage() {
//   const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);

  const days = useMemo(() => {
    const start = startOfMonth(currentMonth);
    const end = endOfMonth(currentMonth);
    const allDays = eachDayOfInterval({ start, end });

    // Pad start of month to align with weekday
    const startDay = start.getDay();
    const paddedDays: (Date | null)[] = Array(startDay).fill(null).concat(allDays);
    return paddedDays;
  }, [currentMonth]);

  const eventsByDate = useMemo(() => {
    const map = new Map<string, typeof events>();
    for (const event of events) {
      if (!event.startDate) continue;
      const key = format(new Date(event.startDate), 'yyyy-MM-dd');
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(event);
    }
    return map;
  }, [events]);

  const selectedEvents = useMemo(() => {
    if (!selectedDate) return [];
    const key = format(selectedDate, 'yyyy-MM-dd');
    return eventsByDate.get(key) ?? [];
  }, [selectedDate, eventsByDate]);

  return (
    <div className="container py-8 text-white">
      <div className="mb-8">
        <h1 className="text-4xl font-extrabold tracking-tight">Event Calendar</h1>
        <p className="text-gray-400 mt-2">Browse upcoming events by date.</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Calendar Grid */}
        <div className="lg:col-span-2">
          <Card className="bg-white/5 border-white/10 text-white">
            <CardHeader className="flex flex-row items-center justify-between">
              <Button variant="ghost" size="icon" onClick={() => setCurrentMonth(subMonths(currentMonth, 1))}>
                <ChevronLeft className="h-5 w-5" />
              </Button>
              <CardTitle className="text-xl">
                {format(currentMonth, 'MMMM yyyy')}
              </CardTitle>
              <Button variant="ghost" size="icon" onClick={() => setCurrentMonth(addMonths(currentMonth, 1))}>
                <ChevronRight className="h-5 w-5" />
              </Button>
            </CardHeader>
            <CardContent>
              {/* Weekday headers */}
              <div className="grid grid-cols-7 gap-1 mb-2">
                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((d) => (
                  <div key={d} className="text-center text-xs font-medium text-gray-500 py-2">{d}</div>
                ))}
              </div>

              {/* Day cells */}
              <div className="grid grid-cols-7 gap-1">
                {days.map((day, i) => {
                  if (!day) return <div key={`pad-${i}`} />;
                  const key = format(day, 'yyyy-MM-dd');
                  const dayEvents = eventsByDate.get(key) ?? [];
                  const isSelected = selectedDate && isSameDay(day, selectedDate);
                  const today = isToday(day);

                  return (
                    <button
                      key={key}
                      onClick={() => setSelectedDate(day)}
                      className={`
                        relative p-2 min-h-[60px] rounded-lg text-left transition-all
                        hover:bg-white/10
                        ${isSelected ? 'bg-cyan-500/20 ring-1 ring-cyan-500' : ''}
                        ${today ? 'border border-cyan-500/40' : ''}
                        ${!isSameMonth(day, currentMonth) ? 'opacity-30' : ''}
                      `}
                    >
                      <span className={`text-sm ${today ? 'text-cyan-400 font-bold' : 'text-gray-300'}`}>
                        {format(day, 'd')}
                      </span>
                      {dayEvents.length > 0 && (
                        <div className="mt-1 flex flex-wrap gap-1">
                          {dayEvents.slice(0, 2).map((e: { _id: string }) => (
                            <div key={e._id} className="w-full h-1.5 rounded-full bg-cyan-500/60" />
                          ))}
                          {dayEvents.length > 2 && (
                            <span className="text-[10px] text-cyan-400">+{dayEvents.length - 2}</span>
                          )}
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Selected Day Events */}
        <div>
          <Card className="bg-white/5 border-white/10 text-white sticky top-8">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-lg">
                <CalendarIcon className="h-5 w-5 text-cyan-400" />
                {selectedDate ? format(selectedDate, 'EEEE, MMMM d') : 'Select a date'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {!selectedDate && (
                <p className="text-gray-500 text-sm">Click a date on the calendar to see events.</p>
              )}
              {selectedDate && selectedEvents.length === 0 && (
                <p className="text-gray-500 text-sm">No events on this date.</p>
              )}
              {selectedEvents.map((event: any) => (
                <Link href={`/events/${event._id}`} key={event._id}>
                  <div className="p-4 rounded-xl bg-white/5 border border-white/10 hover:border-cyan-500/50 transition-all cursor-pointer">
                    <div className="flex items-start justify-between mb-2">
                      <h4 className="font-semibold line-clamp-2">{event.title}</h4>
                      <Badge variant="outline" className="text-[10px] shrink-0 ml-2 border-white/10">
                        {event.category}
                      </Badge>
                    </div>
                    <div className="flex items-center gap-3 text-xs text-gray-400">
                      <span className="flex items-center gap-1">
                        <Clock className="h-3 w-3" />
                        {format(new Date(event.startDate), 'h:mm a')}
                      </span>
                      {event.location?.venue && (
                        <span className="flex items-center gap-1">
                          <MapPin className="h-3 w-3" />
                          {typeof event.location.venue === 'string'
                            ? event.location.venue
                            : event.location.venue?.name ?? 'TBD'}
                        </span>
                      )}
                    </div>
                    {event.capacity && (
                      <div className="mt-2 text-xs text-gray-500">
                        {event.registeredCount ?? 0}/{event.capacity} registered
                      </div>
                    )}
                  </div>
                </Link>
              ))}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
// import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
// import { Button } from '@/components/ui/button';
// import { Badge } from '@/components/ui/badge';
// import { Input } from '@/components/ui/input';
// import { 
//   Award, 
//   Download, 
//   ExternalLink, 
//   Search, 
//   Loader2,
//   Calendar,
//   ShieldCheck,
//   CheckCircle2,
//   XCircle
// } from 'lucide-react';
// import { useAuth } from '@/hooks/use-auth';
import { format } from 'date-fns';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { CertificateViewer } from '@/components/certificates/certificate-card';
import { generateCertificateHtml } from '@/core/utils/certificate-generator';

export function CertificatesClient() {
  const { user } = useAuth();
  const certificates = certificatesRaw ?? [];
  const [searchTerm, setSearchTerm] = useState('');
  const [verifyNumber, setVerifyNumber] = useState('');
  const [verifyResult, setVerifyResult] = useState<any>(null);
  const [verifying, setVerifying] = useState(false);
  
  const [selectedCert, setSelectedCert] = useState<any>(null);
  
  const loading = certificatesRaw === undefined;

  const filteredCertificates = certificates.filter((cert: any) => 
    cert.event?.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    cert.certificateNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDownload = (cert: any) => {
    // Generate a simple text certificate for download
    const content = `
═══════════════════════════════════════════════════
              CERTIFICATE OF COMPLETION
═══════════════════════════════════════════════════

This is to certify that

    ${user?.name ?? 'Attendee'}

has successfully completed

    ${cert.event?.title ?? 'Event'}

Certificate Number: ${cert.certificateNumber}
Issue Date: ${format(cert.issueDate, 'MMMM dd, yyyy')}

${cert.personalizedMessage ? `Message: ${cert.personalizedMessage}` : ''}

Verified by Eventra Platform
═══════════════════════════════════════════════════
    `.trim();

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `certificate-${cert.certificateNumber}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleVerify = async () => {
    if (!verifyNumber.trim()) return;
    setVerifying(true);
    setVerifyResult(null);
    try {
      if (result) {
        setVerifyResult({
          valid: true,
          certificateNumber: result.certificateNumber,
          eventTitle: result.eventTitle ?? 'Unknown',
          userName: result.userName ?? 'Unknown',
          issueDate: result.issueDate,
        });
      } else {
        setVerifyResult({ valid: false });
      }
    } catch {
      setVerifyResult({ valid: false });
    } finally {
      setVerifying(false);
    }
  };

  return (
    <div className="container py-8 space-y-8 text-white">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-extrabold tracking-tight">My Certificates</h1>
          <p className="text-gray-400 mt-2 text-lg">Verified proof of your professional achievements.</p>
        </div>
        <div className="flex gap-2">
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
            <input 
              type="text"
              placeholder="Search by event or ID..." 
              className="w-full pl-10 pr-4 py-2 bg-white/5 border border-white/10 rounded-xl text-white placeholder:text-gray-500 focus:outline-none focus:ring-2 focus:ring-cyan-500/50"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <Dialog>
            <DialogTrigger asChild>
              <Button variant="outline" className="border-white/10 hover:bg-white/10">
                <ShieldCheck className="w-4 h-4 mr-2" /> Verify
              </Button>
            </DialogTrigger>
            <DialogContent className="bg-gray-900 text-white border-white/10">
              <DialogHeader>
                <DialogTitle>Verify Certificate</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div className="flex gap-2">
                  <Input
                    placeholder="Enter certificate number..."
                    value={verifyNumber}
                    onChange={(e) => setVerifyNumber(e.target.value)}
                    className="bg-white/5 border-white/10"
                  />
                  <Button onClick={handleVerify} disabled={verifying}>
                    {verifying ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Verify'}
                  </Button>
                </div>
                {verifyResult && (
                  <div className={`p-4 rounded-lg border ${verifyResult.valid ? 'bg-green-500/10 border-green-500/30' : 'bg-red-500/10 border-red-500/30'}`}>
                    {verifyResult.valid ? (
                      <div className="flex items-start gap-3">
                        <CheckCircle2 className="h-5 w-5 text-green-500 mt-0.5" />
                        <div>
                          <p className="font-medium text-green-400">Valid Certificate</p>
                          <p className="text-sm text-gray-400">Event: {verifyResult.eventTitle}</p>
                          <p className="text-sm text-gray-400">Issued: {format(verifyResult.issueDate, 'MMMM dd, yyyy')}</p>
                        </div>
                      </div>
                    ) : (
                      <div className="flex items-center gap-3">
                        <XCircle className="h-5 w-5 text-red-500" />
                        <p className="text-red-400">Certificate not found</p>
                      </div>
                    )}
                  </div>
                )}
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <Loader2 className="h-8 w-8 animate-spin text-cyan-500" />
        </div>
      ) : filteredCertificates.length === 0 ? (
        <div className="py-24 text-center border border-dashed border-white/10 rounded-3xl bg-white/5">
          <Award size={64} className="mx-auto mb-6 text-gray-700" />
          <h3 className="text-xl font-bold mb-2">No certificates found</h3>
          <p className="text-gray-500 mb-8">Attend events and complete surveys to earn verified certificates.</p>
          <Button variant="outline" className="border-white/20 hover:bg-white/10">Browse Events</Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredCertificates.map((cert: any) => (
            <Card key={cert._id} className="bg-white/5 border-white/10 overflow-hidden group hover:border-cyan-500/50 transition-all duration-300">
              <div className="h-2 bg-gradient-to-r from-cyan-500 to-purple-500" />
              <CardContent className="p-6">
                <div className="flex justify-between items-start mb-6">
                  <div className="bg-cyan-500/10 p-3 rounded-2xl">
                    <Award className="w-8 h-8 text-cyan-400" />
                  </div>
                  <Badge variant="outline" className="text-[10px] uppercase tracking-widest border-white/10 text-gray-400">
                    ID: {cert.certificateNumber}
                  </Badge>
                </div>

                <div className="space-y-4 mb-8">
                  <h3 className="text-xl font-bold line-clamp-2 leading-tight group-hover:text-cyan-400 transition-colors">
                    {cert.event?.title}
                  </h3>
                  
                  <div className="space-y-2">
                    <div className="flex items-center gap-2 text-sm text-gray-400">
                      <Calendar size={14} className="text-gray-600" />
                      <span>Issued on {format(cert.issueDate, 'MMMM dd, yyyy')}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm text-gray-400">
                      <ShieldCheck size={14} className="text-green-500" />
                      <span className="text-green-500/80 font-medium">Verified Completion</span>
                    </div>
                  </div>

                  {cert.personalizedMessage && (
                    <div className="bg-white/5 p-3 rounded-xl border border-white/5">
                      <p className="text-xs text-gray-300 italic">&quot;{cert.personalizedMessage}&quot;</p>
                    </div>
                  )}
                </div>

                <div className="flex gap-2">
                  <Button className="flex-1 bg-white text-black hover:bg-gray-200" onClick={() => setSelectedCert(cert)}>
                    <ExternalLink className="w-4 h-4 mr-2" />
                    View
                  </Button>
                  <Button variant="outline" className="border-white/10 aspect-square p-0 w-10" onClick={() => handleDownload(cert)}>
                    <Download className="w-4 h-4" />
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {selectedCert && (
        <CertificateViewer 
          certificateId={selectedCert.certificateNumber}
          onClose={() => setSelectedCert(null)}
          html={generateCertificateHtml({
            recipientName: user?.name || 'Attendee',
            eventTitle: selectedCert.event?.title || 'Event',
            issueDate: format(selectedCert.issueDate, 'MMMM dd, yyyy'),
            certificateNumber: selectedCert.certificateNumber,
            personalizedMessage: selectedCert.personalizedMessage
          })}
        />
      )}

      {/* Verification Badge */}
      <div className="flex justify-center pt-8">
        <div className="inline-flex items-center gap-3 px-6 py-3 bg-green-500/5 border border-green-500/20 rounded-full">
          <CheckCircle2 className="w-5 h-5 text-green-500" />
          <span className="text-sm font-medium text-green-400">All Eventra certificates are cryptographically verifiable.</span>
        </div>
      </div>
    </div>
  );
}

'use client';
// import { useState } from 'react';
// import { useAuth } from "@/hooks/use-auth";
// import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
// import { Button } from "@/components/ui/button";
// import Image from "next/image";
// import { Check, QrCode } from "lucide-react";
// import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
// import QrScanner from '@/components/check-in/qr-scanner';
// import { useToast } from '@/hooks/use-toast';


export default function CheckInPage() {
    const { user } = useAuth();
    const [isScannerOpen, setIsScannerOpen] = useState(false);
    const { toast } = useToast();
    
    if (!user) return null;

    const isOrganizer = user?.role === 'organizer' || user?.role === 'admin';
    
    // TODO: Fetch tickets and QR URL properly
    const myTickets: any[] = [];
    const firstTicket = myTickets[0];
    const qrData = firstTicket?.ticketNumber ?? user?.id ?? 'NO-TICKET';
    const qrUrl = '/grid.svg'; // Placeholder
    
    const handleScanSuccess = (scannedData: any) => {
        setIsScannerOpen(false);
        toast({
            title: 'Scan Captured',
            description: `Scanned: ${typeof scannedData === 'string' ? scannedData : scannedData?.name ?? 'Unknown'}. Use the Check-in Scanner page for full processing.`,
        });
    };

    return (
        <div className="container py-8">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                <div>
                    <h1 className="text-4xl font-bold font-headline mb-4">{isOrganizer ? 'Check-in Desk' : 'My Check-in'}</h1>
                    <p className="text-muted-foreground mb-8">
                        {isOrganizer ? 'Scan attendee QR codes to check them in.' : 'Present your QR code at the check-in desk.'}
                    </p>
                </div>
                {isOrganizer && (
                    <Dialog open={isScannerOpen} onOpenChange={setIsScannerOpen}>
                        <DialogTrigger asChild>
                            <Button>
                                <QrCode className="mr-2 h-4 w-4" /> Scan Attendee QR Code
                            </Button>
                        </DialogTrigger>
                        <DialogContent>
                            <DialogHeader>
                                <DialogTitle>Scan QR Code</DialogTitle>
                            </DialogHeader>
                            <QrScanner onSuccess={handleScanSuccess} />
                        </DialogContent>
                    </Dialog>
                )}
            </div>
            
            <div className="flex justify-center">
                <Card className="w-full max-w-md text-center glass-effect">
                    <CardHeader>
                        <CardTitle className="font-headline flex items-center justify-center gap-2">
                            <QrCode /> Your Check-in Code
                        </CardTitle>
                        <CardDescription>
                            {firstTicket ? (
                                <>
                                    Status:{' '}
                                    <span className={firstTicket.status === 'checked-in' ? 'text-green-500 font-bold' : 'text-yellow-500 font-bold'}>
                                        {firstTicket.status === 'checked-in' ? ' CHECKED IN' : ' NOT CHECKED IN'}
                                    </span>
                                </>
                            ) : (
                                <span className="text-muted-foreground">No tickets found. Register for an event first.</span>
                            )}
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="flex flex-col items-center gap-6">
                         <div className="p-4 bg-white rounded-lg shadow-inner">
                            <Image
                                src={qrUrl}
                                alt="Registration QR Code"
                                width={300}
                                height={300}
                                className="rounded-md"
                            />
                        </div>
                        <div>
                            <p className="text-sm text-muted-foreground">Ticket Number</p>
                            <p className="font-mono text-2xl font-bold tracking-widest">{qrData}</p>
                        </div>
                        {firstTicket?.event && (
                            <div className="text-sm text-muted-foreground">
                                Event: <span className="font-medium text-foreground">{firstTicket.event.title}</span>
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

'use client';

import React from 'react';
import { useParams } from 'next/navigation';
import { useAuth } from '@/hooks/use-auth';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { BadgeShowcase } from '@/components/gamification/badge-showcase';
import { Loader2, Mail, MapPin, Briefcase, GraduationCap, Calendar, Users } from 'lucide-react';
import { FollowButton } from '@/components/shared/follow-button';

export default function UserProfilePage() {
  const params = useParams();
  const userId = params.id as string;
  const { user: currentUser } = useAuth();


  if (profileUser === undefined) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Loader2 className="h-8 w-8 animate-spin text-cyan-500" />
      </div>
    );
  }

  if (!profileUser) {
    return (
      <div className="flex items-center justify-center min-h-[60vh] text-white">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-2">User Not Found</h2>
          <p className="text-gray-400">This profile doesn't exist or has been removed.</p>
        </div>
      </div>
    );
  }

  const isOwnProfile = currentUser && (currentUser._id === profileUser._id || currentUser.id === profileUser._id);

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl text-white space-y-6">
      {/* Profile Header */}
      <Card className="bg-white/5 border-white/10 text-white overflow-hidden">
        <div className="h-32 bg-gradient-to-r from-cyan-900/50 to-purple-900/50" />
        <CardContent className="p-6 -mt-16">
          <div className="flex flex-col sm:flex-row items-start sm:items-end gap-4">
            <Avatar className="h-24 w-24 border-4 border-[#0a0b14] shadow-lg">
              <AvatarImage src={profileUser.image} />
              <AvatarFallback className="bg-cyan-500/20 text-cyan-400 text-2xl font-bold">
                {profileUser.name?.charAt(0) || '?'}
              </AvatarFallback>
            </Avatar>
            <div className="flex-1">
              <h1 className="text-2xl font-bold">{profileUser.name || 'Anonymous'}</h1>
              <div className="flex flex-wrap items-center gap-3 mt-1 text-sm text-gray-400">
                {profileUser.role && (
                  <Badge variant="secondary" className="bg-cyan-500/10 text-cyan-400 border-cyan-500/20 capitalize">
                    {profileUser.role}
                  </Badge>
                )}
                {followStats && (
                  <div className="flex items-center gap-3 text-xs">
                    <span className="text-white font-bold">{followStats.followerCount} <span className="text-gray-500 font-normal">followers</span></span>
                    <span className="text-white font-bold">{followStats.followingCount} <span className="text-gray-500 font-normal">following</span></span>
                  </div>
                )}
              </div>
            </div>
            {!isOwnProfile && profileUser?._id && (
              <div className="pb-1">
                <FollowButton userId={profileUser._id} />
              </div>
            )}
          </div>

          {(profileUser as any).bio && (
            <p className="mt-4 text-gray-300 text-sm leading-relaxed">{(profileUser as any).bio}</p>
          )}

          {/* Stats row */}
          {stats && (
            <div className="grid grid-cols-3 gap-4 mt-6">
              <div className="text-center p-3 bg-white/5 rounded-lg">
                <p className="text-2xl font-bold text-cyan-400">{stats.level || 1}</p>
                <p className="text-xs text-gray-500">Level</p>
              </div>
              <div className="text-center p-3 bg-white/5 rounded-lg">
                <p className="text-2xl font-bold text-purple-400">{stats.xp || 0}</p>
                <p className="text-xs text-gray-500">XP</p>
              </div>
              <div className="text-center p-3 bg-white/5 rounded-lg">
                <p className="text-2xl font-bold text-amber-400">{stats.badgeCount || 0}</p>
                <p className="text-xs text-gray-500">Badges</p>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Badges */}
      <BadgeShowcase userId={profileUser._id} />

      {/* Member since */}
      <Card className="bg-white/5 border-white/10 text-white">
        <CardContent className="p-6">
          <div className="flex items-center gap-2 text-sm text-gray-400">
