            <Copy className="h-4 w-4" />
          </Button>
        </div>
      </CardContent>

      <CardFooter className="flex gap-2">
        <Button variant="outline" className="flex-1" onClick={onDownload}>
          <Download className="h-4 w-4 mr-2" />
