  );
}

'use client';
// 
// import { useState, useEffect, useRef, useCallback } from 'react';
// import { useAuth } from '@/hooks/use-auth';
import { EventTicket, Event } from '@/types';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Dialog,
  DialogContent,
} from '@/components/ui/dialog';
import {
  Camera,
  QrCode,
  Search,
  CheckCircle2,
  XCircle,
  Loader2,
  ScanLine,
  UserCheck,
  Volume2,
  VolumeX
} from 'lucide-react';
import { cn, getErrorMessage } from '@/core/utils/utils';
import { format } from 'date-fns';
import { useToast } from '@/hooks/use-toast';
import { Progress } from '@/components/ui/progress';
import { Activity, TrendingUp, Clock } from 'lucide-react';

type ScanResult = {
  success: boolean;
  ticket?: any;
  message: string;
  timestamp: Date;
};

export default function CheckInScannerClient() {
  const { user } = useAuth();
  const { toast } = useToast();
//   
  
  const [selectedEvent, setSelectedEvent] = useState<string>('');
  const [scanning, setScanning] = useState(false);
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
  const [manualSearch, setManualSearch] = useState('');
  const [soundEnabled, setSoundEnabled] = useState(true);
  
  const scannerRef = useRef<any>(null);

  const allEventsRaw: any[] = [];
  const checkInTicketMutation = async (data: any) => ({ ticket: {} });

  const events: Event[] = (allEventsRaw || []).map((e: any) => ({ ...e, id: e._id }));
  const organizerEvents = events.filter(e => e.organizerId === (user?._id || user?.id) || user?.role === 'admin');

  // Dashboard Queries
  const checkInCount = 0;
  const totalRegistrations = 0;
  const checkInRate = 0;

  useEffect(() => {
    if (organizerEvents.length > 0 && !selectedEvent) {
      setSelectedEvent(organizerEvents[0].id);
    }
  }, [organizerEvents, selectedEvent]);

  const handleProcessCheckIn = async (ticketNumber: string) => {
    try {
      const response = await checkInTicketMutation({ 
        ticketNumber,
        eventId: selectedEvent ? (selectedEvent as any) : undefined,
      });
      const result: ScanResult = {
        success: true,
        ticket: response.ticket,
        message: 'Successfully checked in!',
        timestamp: new Date()
      };
      setScanResult(result);
      if (soundEnabled) {
          // Play beep sound logic could go here
      }
    } catch (error: unknown) {
      const result: ScanResult = { 
        success: false, 
        message: getErrorMessage(error), 
        timestamp: new Date() 
      };
      setScanResult(result);
    }
  };

  const startScanner = useCallback(async () => {
    try {
      const { Html5Qrcode } = await import('html5-qrcode');
      const html5QrCode = new Html5Qrcode("qr-reader");
      scannerRef.current = html5QrCode;
      await html5QrCode.start(
        { facingMode: "environment" }, 
        { fps: 10, qrbox: 250 }, 
        (decodedText) => {
            stopScanner();
            handleProcessCheckIn(decodedText);
        }, 
        () => {}
      );
      setScanning(true);
    } catch (err) {
      console.error(err);
      toast({ title: 'Camera Error', variant: 'destructive' });
    }
  }, [toast]);

  const stopScanner = useCallback(async () => {
    if (scannerRef.current) {
      try {
        await scannerRef.current.stop();
      } catch (e) {}
      scannerRef.current = null;
      setScanning(false);
    }
  }, []);

  if (!user || (user.role !== 'organizer' && user.role !== 'admin')) {
    return (
      <div className="container py-16 text-center text-white">
        <ScanLine className="h-16 w-16 mx-auto mb-6 text-muted-foreground opacity-20" />
        <h1 className="text-2xl font-bold">Organizer Access Required</h1>
        <Button asChild className="mt-4" variant="outline"><a href="/explore">Back to Explore</a></Button>
      </div>
    );
  }

  return (
    <div className="container py-8 max-w-4xl text-white">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold">Check-in Scanner</h1>
        <Button variant="outline" size="icon" className="border-white/10" onClick={() => setSoundEnabled(!soundEnabled)}>
          {soundEnabled ? <Volume2 className="h-4 w-4" /> : <VolumeX className="h-4 w-4" />}
        </Button>
      </div>

      <Card className="mb-6 bg-white/5 border-white/10 text-white">
        <CardContent className="p-4">
          <Label className="mb-2 block text-gray-400">Select Event</Label>
          <Select value={selectedEvent} onValueChange={setSelectedEvent}>
            <SelectTrigger className="bg-white/5 border-white/10"><SelectValue placeholder="Choose an event" /></SelectTrigger>
            <SelectContent className="bg-gray-900 text-white">
              {organizerEvents.map(event => <SelectItem key={event.id} value={event.id}>{event.title}</SelectItem>)}
            </SelectContent>
          </Select>
        </CardContent>
      </Card>

      {/* Real-time Stats Dashboard */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <Card className="bg-white/5 border-white/10 text-white overflow-hidden group hover:border-emerald-500/30 transition-colors">
          <CardContent className="p-6 relative">
            <div className="flex justify-between items-start mb-2">
              <p className="text-[10px] uppercase font-black text-gray-500 tracking-widest">Checked In</p>
              <UserCheck size={14} className="text-emerald-400" />
            </div>
            <p className="text-3xl font-black">{checkInCount} / {totalRegistrations}</p>
            <div className="mt-4 h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
              <div className="h-full bg-emerald-500 rounded-full transition-all duration-1000" style={{ width: `${checkInRate}%` }} />
            </div>
          </CardContent>
        </Card>
        
        <Card className="bg-white/5 border-white/10 text-white group hover:border-cyan-500/30 transition-colors">
          <CardContent className="p-6">
            <div className="flex justify-between items-start mb-2">
              <p className="text-[10px] uppercase font-black text-gray-500 tracking-widest">Check-in Rate</p>
              <TrendingUp size={14} className="text-cyan-400" />
            </div>
            <p className="text-3xl font-black">{checkInRate}%</p>
            <p className="text-[10px] text-gray-500 mt-1 flex items-center gap-1">
              <Activity size={10} className="text-cyan-500 animate-pulse" /> Live activity tracking
            </p>
          </CardContent>
        </Card>

        <Card className="bg-white/5 border-white/10 text-white group hover:border-amber-500/30 transition-all">
          <CardContent className="p-6">
            <div className="flex justify-between items-start mb-2">
              <p className="text-[10px] uppercase font-black text-gray-500 tracking-widest">Pending</p>
              <Clock size={14} className="text-amber-400" />
            </div>
            <p className="text-3xl font-black">{totalRegistrations - checkInCount}</p>
            <p className="text-[10px] text-gray-500 mt-1">Remaining attendees</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <Card className="bg-white/5 border-white/10 text-white">
          <CardHeader><CardTitle>QR Scanner</CardTitle></CardHeader>
          <CardContent>
            <div id="qr-reader" className="relative w-full aspect-square rounded-lg bg-black flex items-center justify-center border border-white/5 overflow-hidden">
              {!scanning && <QrCode className="h-16 w-16 text-gray-700" />}
            </div>
            <Button onClick={scanning ? stopScanner : startScanner} className="w-full mt-4" variant={scanning ? "destructive" : "default"}>
              {scanning ? "Stop Scanner" : "Start Scanner"}
            </Button>
          </CardContent>
        </Card>

        <Card className="bg-white/5 border-white/10 text-white">
          <CardHeader><CardTitle>Manual Check-in</CardTitle></CardHeader>
          <CardContent>
            <div className="flex gap-2 mb-4">
              <Input 
                placeholder="Ticket Number..." 
                value={manualSearch} 
                onChange={(e) => setManualSearch(e.target.value)} 
                className="bg-white/5 border-white/10"
              />
              <Button onClick={() => handleProcessCheckIn(manualSearch)}><UserCheck className="h-4 w-4" /></Button>
            </div>
            <div className="py-10 text-center text-gray-500 border border-dashed border-white/10 rounded-lg">
                <Search size={32} className="mx-auto mb-2 opacity-20" />
                <p className="text-sm">Enter a ticket number manually to process check-in.</p>
            </div>
          </CardContent>
        </Card>
      </div>

      <Dialog open={!!scanResult} onOpenChange={() => setScanResult(null)}>
        <DialogContent className="sm:max-w-md text-center py-10 bg-gray-900 text-white border-white/10">
          {scanResult?.success ? (
            <div className="space-y-4">
                <CheckCircle2 className="h-20 w-20 text-emerald-500 mx-auto" />
                <h2 className="text-2xl font-bold">Check-in Success!</h2>
                <div className="p-4 bg-white/5 rounded-lg border border-white/10 text-left">
                    <p className="text-xs text-gray-400 uppercase">Ticket Number</p>
                    <p className="font-mono text-cyan-400">{scanResult.ticket?.ticketNumber}</p>
                </div>
            </div>
          ) : (
            <div className="space-y-4">
                <XCircle className="h-20 w-20 text-destructive mx-auto" />
                <h2 className="text-2xl font-bold">Check-in Failed</h2>
                <p className="text-gray-400">{scanResult?.message}</p>
            </div>
          )}
          <Button onClick={() => setScanResult(null)} className="mt-8 w-full">Continue Scanning</Button>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
// import { useRouter } from 'next/navigation';
// import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
// import { Badge } from '@/components/ui/badge';
// import { Button } from '@/components/ui/button';
// import { Input } from '@/components/ui/input';
// import { Textarea } from '@/components/ui/textarea';
// import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
// import { 
//   Users, MessageSquare, Plus, Search, ChevronRight, Lock, Calendar, Loader2, CheckCircle2,
//   MoreVertical, ThumbsUp, MessageCircle, Flag, Info
// } from 'lucide-react';
// import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';
import { moderateContent } from '@/app/actions/moderation';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

export function CommunityDetailClient({ communityId }: { communityId: string }) {
  const { user } = useAuth();
  const router = useRouter();
  const { toast } = useToast();
//   
//   
//     { communityId: communityId as any },
//     { initialNumItems: 10 }
//   );
// 
//     { communityId: communityId as any },
//     { initialNumItems: 20 }
//   );
// 
  
  const [showCreatePost, setShowCreatePost] = useState(false);
  const [newPostContent, setNewPostContent] = useState('');
  const [loading, setLoading] = useState(false);

  const isMember = !!memberStatus;

  const handleJoin = async () => {
    try {
      await joinMutation({ id: communityId as any });
      toast({ title: 'Joined community! 🎉' });
    } catch (e) {
      toast({ title: 'Failed to join', variant: 'destructive' });
    }
  };

  const handleLike = async (postId: string) => {
    try {
      await likePostMutation({ id: postId as any });
    } catch (e) {
      toast({ title: 'Failed to like post' });
    }
  };

  const handleCreatePost = async () => {
    if (!newPostContent.trim()) return;
    setLoading(true);
    try {
      // 1. Create Post
      const postId = await createPostMutation({ 
        content: newPostContent,
        communityId: communityId as any 
      });
      
      setShowCreatePost(false);
      setNewPostContent('');
      toast({ title: 'Posted successfully' });

      // 2. Async AI Moderation check
      const moderation = await moderateContent(newPostContent, user?.name);
      if (moderation.success && moderation.isFlagged) {
        await flagPostMutation({
          postId: postId as any,
          reason: moderation.reason || 'AI Flagged'
        });
        toast({ 
          title: 'Post Flagged', 
          description: 'Your post is under review by our AI moderator.',
          variant: 'destructive' 
        });
      }
    } catch (e) {
      toast({ title: 'Failed to post', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  if (community === undefined) return <div className="flex items-center justify-center min-h-[400px] text-white"><Loader2 className="animate-spin" /></div>;
  if (community === null) return <div className="p-20 text-center text-white">Community not found</div>;

  return (
    <div className="container mx-auto px-4 py-6 text-white space-y-6">
      <Card className="bg-white/5 border-white/10 text-white">
        <CardHeader>
          <div className="flex flex-col md:flex-row justify-between items-start gap-4">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-xl bg-cyan-500/10 flex items-center justify-center text-cyan-400 font-bold text-2xl border border-cyan-500/20">
                {community.name.charAt(0)}
              </div>
              <div>
                <CardTitle className="text-3xl font-bold">{community.name}</CardTitle>
                <CardDescription className="text-gray-400 mt-1">{community.category} Community</CardDescription>
              </div>
            </div>
            <div className="flex gap-2">
                {isMember ? (
                    <>
                        <Button onClick={() => setShowCreatePost(true)} className="bg-cyan-600 hover:bg-cyan-500"><Plus className="mr-2 h-4 w-4" /> New Post</Button>
                        <Badge variant="secondary" className="bg-green-500/20 text-green-400 border-green-500/20 py-2 px-4 gap-2">
                            <CheckCircle2 size={14} /> Member
                        </Badge>
                    </>
                ) : (
                    <Button onClick={handleJoin} className="bg-cyan-600 hover:bg-cyan-500">Join Community</Button>
                )}
            </div>
          </div>
          <div className="flex gap-6 mt-4 pt-4 border-t border-white/10 text-sm text-gray-400">
            <span className="flex items-center gap-1"><Users size={14} className="text-cyan-400" /> {community.membersCount} members</span>
            <span className="flex items-center gap-1"><Lock size={14} className={community.isPrivate ? "text-amber-500" : "text-green-500"} /> {community.isPrivate ? "Private" : "Public"}</span>
          </div>
        </CardHeader>
      </Card>

      <Tabs defaultValue="feed" className="space-y-6">
        <TabsList className="bg-white/5 border-white/10 p-1">
          <TabsTrigger value="feed" className="data-[state=active]:bg-cyan-600">Feed</TabsTrigger>
          <TabsTrigger value="members" className="data-[state=active]:bg-cyan-600">Members</TabsTrigger>
          <TabsTrigger value="about" className="data-[state=active]:bg-cyan-600">About</TabsTrigger>
        </TabsList>

        <TabsContent value="feed" className="space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-4">
                {posts.map((p: any) => (
                <Card key={p._id} className="bg-white/5 border-white/10 text-white overflow-hidden">
                    <CardHeader className="p-4 flex flex-row items-center gap-3">
                      <Avatar className="h-8 w-8">
                        <AvatarImage src={p.authorImage} />
                        <AvatarFallback className="bg-cyan-500/10 text-cyan-500 text-[10px]">{p.authorName?.charAt(0)}</AvatarFallback>
                      </Avatar>
                      <div className="flex-1">
                        <p className="text-sm font-bold">{p.authorName}</p>
                        <p className="text-[10px] text-gray-500">{new Date(p.createdAt).toLocaleDateString()}</p>
                      </div>
                      <Button variant="ghost" size="icon" className="h-8 w-8 text-gray-500"><MoreVertical size={14} /></Button>
                    </CardHeader>
                    <CardContent className="p-4 pt-0">
                        <p className="text-gray-200 whitespace-pre-wrap">{p.content}</p>
                        {p.imageUrl && (
                          <div className="mt-4 rounded-lg overflow-hidden border border-white/10">
                            <img src={p.imageUrl} alt="Post content" className="w-full h-auto object-cover max-h-[400px]" />
                          </div>
                        )}
                        
                        <div className="flex items-center gap-4 mt-6 pt-4 border-t border-white/5">
                          <Button 
                            variant="ghost" 
                            size="sm" 
                            className={p.meLiked ? "text-cyan-400" : "text-gray-500"}
                            onClick={() => handleLike(p._id)}
                          >
                            <ThumbsUp className="mr-2 h-4 w-4" /> {p.likes || 0}
                          </Button>
                          <Button variant="ghost" size="sm" className="text-gray-500">
                            <MessageCircle className="mr-2 h-4 w-4" /> {p.commentCount || 0}
                          </Button>
                        </div>
                    </CardContent>
                </Card>
                ))}

                {posts.length === 0 && postsStatus !== "LoadingFirstPage" && (
                  <div className="py-20 text-center text-gray-500 border border-dashed border-white/10 rounded-lg italic">
                    No posts yet. Be the first to share something!
                  </div>
                )}

                {postsStatus === "CanLoadMore" && (
                  <div className="flex justify-center pt-4">
                    <Button variant="outline" onClick={() => loadMorePosts(10)} className="border-white/10">Load More Posts</Button>
                  </div>
                )}

                {(postsStatus === "LoadingMore" || postsStatus === "LoadingFirstPage") && (
                  <div className="flex justify-center pt-4"><Loader2 className="animate-spin text-cyan-500" /></div>
                )}
            </div>
            
            <div className="space-y-4">
                <Card className="bg-white/5 border-white/10 text-white">
                    <CardHeader><CardTitle className="text-sm">About Community</CardTitle></CardHeader>
                    <CardContent className="p-4 pt-0 text-sm text-gray-400">
                        <p>{community.description}</p>
                        <div className="mt-4 space-y-2">
                          <div className="flex items-center gap-2">
                            <Calendar size={14} className="text-cyan-400" />
                            <span>Created {new Date(community._creationTime).toLocaleDateString()}</span>
                          </div>
                          <div className="flex items-center gap-2">
                            <Info size={14} className="text-cyan-400" />
                            <span>Category: {community.category}</span>
                          </div>
                        </div>
                    </CardContent>
                </Card>
            </div>
          </div>
        </TabsContent>

        <TabsContent value="members">
          <Card className="bg-white/5 border-white/10 text-white">
            <CardHeader><CardTitle>Members ({community.membersCount})</CardTitle></CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {members.map((m: any) => (
                  <div key={m._id} className="flex items-center gap-3 p-3 rounded-xl bg-white/5 border border-white/10">
                    <Avatar>
                      <AvatarImage src={m.image} />
                      <AvatarFallback className="bg-cyan-500/10 text-cyan-500">{m.name?.charAt(0)}</AvatarFallback>
                    </Avatar>
                    <div className="overflow-hidden">
                      <p className="text-sm font-bold truncate">{m.name}</p>
                      <p className="text-[10px] text-cyan-400 uppercase tracking-wider font-mono">{m.role}</p>
                    </div>
                  </div>
                ))}
              </div>

              {membersStatus === "CanLoadMore" && (
                <div className="flex justify-center mt-6">
                  <Button variant="outline" onClick={() => loadMoreMembers(20)} className="border-white/10">Load More Members</Button>
                </div>
              )}

              {(membersStatus === "LoadingMore" || membersStatus === "LoadingFirstPage") && (
                <div className="flex justify-center mt-6"><Loader2 className="animate-spin text-cyan-500" /></div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="about">
           <Card className="bg-white/5 border-white/10 text-white">
              <CardHeader><CardTitle>About {community.name}</CardTitle></CardHeader>
              <CardContent className="space-y-4">
                <p className="text-gray-300 leading-relaxed">{community.description}</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6 border-t border-white/10">
                   <div>
                     <h4 className="font-bold mb-2">Platform Guidelines</h4>
                     <p className="text-sm text-gray-400">Be respectful, stay on topic, and help grow the community. All posts are subject to AI moderation for platform safety.</p>
                   </div>
                   <div>
                     <h4 className="font-bold mb-2">Moderation</h4>
                     <p className="text-sm text-gray-400">This community is moderated by its creator and automated AI tools. Violating content will be flagged and removed.</p>
                   </div>
                </div>
              </CardContent>
           </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={showCreatePost} onOpenChange={setShowCreatePost}>
        <DialogContent className="bg-gray-900 border-white/10 text-white">
          <DialogHeader><DialogTitle>Create Community Post</DialogTitle></DialogHeader>
          <Textarea 
            value={newPostContent} 
            onChange={e => setNewPostContent(e.target.value)} 
            placeholder="Share with your community..." 
            className="bg-white/5 border-white/10 min-h-[150px]" 
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreatePost(false)}>Cancel</Button>
            <Button onClick={handleCreatePost} disabled={loading}>{loading ? 'Posting...' : 'Post'}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
// import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
// import { Badge } from '@/components/ui/badge';
// import { Button } from '@/components/ui/button';
// import { Input } from '@/components/ui/input';
// import { Textarea } from '@/components/ui/textarea';
// import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
// import { 
//   Users, MessageSquare, Plus, Search, ChevronRight, Lock, Loader2
// } from 'lucide-react';
// import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';

export function CommunityListClient() {
  const { user } = useAuth();
  const { toast } = useToast();
  
  const [searchTerm, setSearchTerm] = useState('');
//     { search: searchTerm || undefined },
//     { initialNumItems: 12 }
//   );
//   
  
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const [newCommunity, setNewCommunity] = useState({
    name: '',
    description: '',
    category: 'General',
    isPrivate: false
  });

  const handleCreateCommunity = async () => {
    if (!newCommunity.name.trim()) return;
    setLoading(true);
    try {
      await createCommunityMutation(newCommunity);
      setShowCreateDialog(false);
      setNewCommunity({ name: '', description: '', category: 'General', isPrivate: false });
      toast({ title: 'Community created' });
    } catch (e) {
      toast({ title: 'Failed to create', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container mx-auto px-4 py-6 text-white">
      <div className="flex justify-between items-center mb-8">
        <div><h1 className="text-3xl font-bold">Communities</h1><p className="text-gray-400">Join discussions and connect</p></div>
        <Button onClick={() => setShowCreateDialog(true)}><Plus className="w-4 h-4 mr-2" /> Create</Button>
      </div>

      <div className="relative mb-8">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 w-4 h-4" />
        <Input 
          placeholder="Search communities..." 
          value={searchTerm} 
          onChange={e => setSearchTerm(e.target.value)} 
          className="pl-10 bg-white/5 border-white/10" 
        />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        {communitiesRaw.map((c: any) => (
          <Link key={c._id} href={`/community/${c._id}`}>
            <Card className="bg-white/5 border-white/10 hover:bg-white/10 transition-colors cursor-pointer text-white h-full flex flex-col">
              <CardHeader>
                <div className="flex justify-between items-start">
                  <CardTitle className="line-clamp-1">{c.name}</CardTitle>
                  <Badge variant="secondary">{c.category}</Badge>
                </div>
                <CardDescription className="text-gray-400 line-clamp-2">{c.description}</CardDescription>
              </CardHeader>
              <CardContent className="mt-auto pt-4 border-t border-white/5 flex items-center justify-between text-sm text-gray-500">
                <div className="flex gap-4">
                  <div className="flex items-center gap-1">
                    <Users size={14} /> {c.membersCount}
                  </div>
                  {c.isPrivate && <Lock size={14} className="text-amber-500" />}
                </div>
                <ChevronRight size={16} />
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>

      {communitiesRaw.length === 0 && status !== "LoadingFirstPage" && (
        <div className="py-20 text-center text-gray-500 border border-dashed border-white/10 rounded-lg">
          No communities found.
        </div>
      )}

      {status === "CanLoadMore" && (
        <div className="mt-8 flex justify-center">
          <Button variant="outline" onClick={() => loadMore(12)} className="border-white/10">
            Load More
          </Button>
        </div>
      )}

      {(status === "LoadingMore" || status === "LoadingFirstPage") && (
        <div className="mt-8 flex justify-center">
          <Loader2 className="h-6 w-6 animate-spin text-cyan-500" />
        </div>
      )}

      <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
        <DialogContent className="bg-gray-900 text-white border-white/10">
          <DialogHeader>
            <DialogTitle>Create New Community</DialogTitle>
            <DialogDescription>
              Connect with like-minded people.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
             <Input 
               placeholder="Community Name" 
               value={newCommunity.name} 
               onChange={(e) => setNewCommunity({...newCommunity, name: e.target.value})} 
               className="bg-white/5 border-white/10"
             />
             <Textarea 
               placeholder="Description" 
               value={newCommunity.description} 
               onChange={(e) => setNewCommunity({...newCommunity, description: e.target.value})} 
               className="bg-white/5 border-white/10"
             />
             <Input 
               placeholder="Category" 
               value={newCommunity.category} 
               onChange={(e) => setNewCommunity({...newCommunity, category: e.target.value})} 
               className="bg-white/5 border-white/10"
             />
             <div className="flex items-center gap-2">
               <input 
                 type="checkbox" 
                 checked={newCommunity.isPrivate} 
                 onChange={(e) => setNewCommunity({...newCommunity, isPrivate: e.target.checked})} 
                 className="rounded border-gray-600 bg-gray-700"
               />
               <span className="text-sm">Private Community</span>
             </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreateDialog(false)} className="border-white/10">Cancel</Button>
            <Button onClick={handleCreateCommunity} disabled={loading} className="bg-cyan-600 hover:bg-cyan-500">
              {loading ? 'Creating...' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

