// import { useToast } from '@/hooks/use-toast';
import { EventChatbot, ChatbotTrigger } from '@/components/ai/event-chatbot';
import { Progress } from '@/components/ui/progress';
import { createCheckoutSession } from '@/app/actions/payments';
import { EventDiscussionBoard } from './event-discussion-board';
import { EventReactions } from './event-reactions';
import { EventGallery } from './event-gallery';
import { EventPolls } from './event-polls';
import { AnnouncementBanner } from './announcement-banner';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Tag } from 'lucide-react';

import { generateEventSummary } from '@/app/actions/event-insights';
import { Sparkles, MessageSquare } from 'lucide-react';

export default function EventDetailsClient({ eventId }: { eventId: string }) {
  const router = useRouter();
  const { user, updateUser } = useAuth();
  const { toast } = useToast();
// 
  
  const [registering, setRegistering] = useState(false);
  const [cloning, setCloning] = useState(false);
  const [showChatbot, setShowChatbot] = useState(false);
  const [activeTab, setActiveTab] = useState('about');
  const [showTierSelection, setShowTierSelection] = useState(false);
  const [discountCode, setDiscountCode] = useState('');
  const [isValidatingDiscount, setIsValidatingDiscount] = useState(false);
  const [appliedDiscount, setAppliedDiscount] = useState<any>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);

  const handleGenerateSummary = async () => {
    setGeneratingSummary(true);
    try {
      const result = await generateEventSummary(eventId);
      if (result.success) {
        toast({ title: 'Summary generated! ✨', description: 'View it in the About tab.' });
        setActiveTab('about');
      } else {
        throw new Error(result.error);
      }
    } catch (e: any) {
      toast({ title: 'Generation failed', description: e.message, variant: 'destructive' });
    } finally {
      setGeneratingSummary(false);
    }
  };
// 
//     code: discountCode, 
//     eventId: eventId as any 
//   });

  const handleApplyDiscount = () => {
    if (!discountCode) return;
    setIsValidatingDiscount(true);
    // The query automatically updates, we just check the result
    if (validateDiscount?.valid) {
      setAppliedDiscount(validateDiscount);
      toast({ title: 'Discount applied! 🎫' });
    } else {
      setAppliedDiscount(null);
      toast({ 
        title: 'Invalid code', 
        description: validateDiscount?.message || 'Please check the code and try again',
        variant: 'destructive' 
      });
    }
    setIsValidatingDiscount(false);
  };

  const handleRegister = async (tierName?: string) => {
    if (!user) {
      router.push(`/login?callbackUrl=/events/${eventId}`);
      return;
    }
    
    // If event has tiers and no tier is selected, show selection
    if (!tierName && event?.ticketTiers && event.ticketTiers.length > 0) {
      setShowTierSelection(true);
      return;
    }
    
    setRegistering(true);
    setShowTierSelection(false);
    try {
      // Determine if it's a paid flow
      let isPaid = event?.isPaid;
      let price = event?.price;
      
      if (tierName && event?.ticketTiers) {
        const tier = (event.ticketTiers as any[]).find((t: any) => t.name === tierName);
        if (tier) {
          isPaid = tier.price > 0;
          price = tier.price;
        }
      }

      if (isPaid && price && price > 0) {
        // Stripe Flow
        const { url } = await createCheckoutSession(
          eventId, 
          user._id || user.id, 
          tierName, 
          appliedDiscount ? discountCode : undefined
        );
        if (url) {
          window.location.href = url;
        } else {
          throw new Error("Failed to create checkout session");
        }
      } else {
        // Free Registration Flow
        await registerMutation({ eventId: eventId as any, tierName });
        toast({ title: 'Registered! 🎉' });
      }
    } catch (e: any) {
      console.error(e);
      toast({ title: 'Registration Failed', description: e.message || "Please try again", variant: 'destructive' });
    } finally {
      setRegistering(false);
    }
  };

  const handleClone = async () => {
    setCloning(true);
    try {
      const newId = await cloneEventMutation({ id: eventId as any });
      toast({ title: 'Event cloned successfully! 📋', description: 'Redirecting to the new event editor.' });
      router.push(`/events/${newId}/edit`);
    } catch (e: any) {
      toast({ title: 'Clone failed', description: e.message, variant: 'destructive' });
    } finally {
      setCloning(false);
    }
  };


  if (event === undefined) return <div className="flex items-center justify-center min-h-screen text-white">Loading...</div>;
  if (event === null) return <div className="flex items-center justify-center min-h-screen text-white">Event Not Found</div>;

  const isRegistered = !!registration;
  const isOrganizer = user && (user._id === event.organizerId || user.role === 'admin');
  const capacityPercent = event.capacity > 0 ? Math.min(100, Math.round((event.registeredCount / event.capacity) * 100)) : 0;
  const isFull = event.registeredCount >= event.capacity;

  const locationDisplay = typeof event.location === 'string'
    ? event.location
    : event.location?.venue
      ? (typeof event.location.venue === 'string' ? event.location.venue : event.location.venue?.name ?? '')
      : '';

  return (
    <div className="min-h-screen bg-black text-white pb-20">
      <div className="h-[300px] bg-gradient-to-br from-cyan-900/50 to-purple-900/50 relative">
        <div className="absolute top-4 left-4"><Button variant="ghost" onClick={() => router.back()}><ArrowLeft className="mr-2 h-4 w-4" /> Back</Button></div>
        {isOrganizer && (
          <div className="absolute top-4 right-4 flex items-center gap-2">
            <Button 
              variant="outline" 
              className="border-white/20 hover:bg-white/10"
              onClick={handleClone}
              disabled={cloning}
            >
              {cloning ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Copy className="mr-2 h-4 w-4" />}
              Clone
            </Button>
            <Button variant="outline" asChild className="border-white/20 hover:bg-white/10">
              <Link href={`/events/${eventId}/edit`}><Edit className="mr-2 h-4 w-4" /> Edit Event</Link>
            </Button>
          </div>
        )}
      </div>
      <div className="container -mt-20 relative z-10">
        <div className="grid lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
            <AnnouncementBanner eventId={event._id} />
            <Card className="bg-white/5 border-white/10 text-white">
              <CardContent className="p-8">
                <div className="flex items-center gap-2 mb-4">
                  <Badge className="bg-cyan-500/20 text-cyan-300 border-cyan-500/30">{event.category}</Badge>
                  <Badge variant="outline" className="border-white/20 text-gray-300">{event.type}</Badge>
                  {event.status === 'cancelled' && <Badge variant="destructive">Cancelled</Badge>}
                </div>
                <h1 className="text-4xl font-bold mb-6">{event.title}</h1>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="flex items-center gap-3"><Calendar className="text-cyan-400" /> <div><p className="text-xs text-gray-400">Date</p><p className="font-medium">{new Date(event.startDate).toLocaleDateString()}</p></div></div>
                  {locationDisplay && (
                    <div className="flex items-center gap-3"><MapPin className="text-cyan-400" /> <div><p className="text-xs text-gray-400">Location</p><p className="font-medium">{locationDisplay}</p></div></div>
                  )}
                  <div className="flex items-center gap-3"><Users className="text-cyan-400" /> <div><p className="text-xs text-gray-400">Attendees</p><p className="font-medium">{event.registeredCount} / {event.capacity}</p></div></div>
                </div>

                {/* Capacity Progress */}
                <div className="mt-6">
                  <div className="flex items-center justify-between text-sm mb-2">
                    <span className="text-gray-400">Capacity</span>
                    <span className={cn("font-medium", isFull ? "text-red-400" : capacityPercent > 80 ? "text-amber-400" : "text-cyan-400")}>
                      {isFull ? 'Sold Out' : `${event.capacity - event.registeredCount} spots left`}
                    </span>
                  </div>
                  <Progress value={capacityPercent} className="h-2" />
                </div>

                <EventReactions eventId={event._id} />

                <div className="mt-6">
                  <Tabs value={activeTab} onValueChange={setActiveTab}>
                    <TabsList className="bg-white/5 border-white/10 text-white p-1 mb-6">
                      <TabsTrigger value="about" className="data-[state=active]:bg-cyan-600">About</TabsTrigger>
                      <TabsTrigger value="agenda" className="data-[state=active]:bg-cyan-600">Agenda</TabsTrigger>
                      <TabsTrigger value="discussion" className="data-[state=active]:bg-cyan-600 flex items-center gap-2">
                        Discussion
                        <Badge variant="secondary" className="h-4 p-0 px-1 text-[8px] bg-white/10 text-gray-400">NEW</Badge>
                      </TabsTrigger>
                      <TabsTrigger value="photos" className="data-[state=active]:bg-cyan-600">Photos</TabsTrigger>
                      <TabsTrigger value="polls" className="data-[state=active]:bg-cyan-600 flex items-center gap-2">
                        Polls
                        <div className="h-1.5 w-1.5 rounded-full bg-red-500 animate-pulse" />
                      </TabsTrigger>
                    </TabsList>

                    <TabsContent value="about" className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                      {event.summary && (
                        <div className="p-6 bg-cyan-500/5 border border-cyan-500/20 rounded-2xl space-y-4">
                          <h3 className="text-lg font-bold flex items-center gap-2 text-cyan-400">
                            <Sparkles className="h-5 w-5" />
                            Event Summary
                          </h3>
                          <div className="text-gray-300 whitespace-pre-wrap leading-relaxed">
                            {event.summary}
                          </div>
                        </div>
                      )}
                      
                      <div className="flex justify-between items-center">
                        <h3 className="font-bold">About the Event</h3>
                        {isOrganizer && (new Date().getTime() > event.endDate) && !event.summary && (
                          <Button 
                            variant="outline" 
                            size="sm" 
                            className="border-cyan-500/30 text-cyan-400 hover:bg-cyan-500/10"
                            onClick={handleGenerateSummary}
                            disabled={generatingSummary}
                          >
                            {generatingSummary ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Sparkles className="h-4 w-4 mr-2" />}
                            Generate AI Summary
                          </Button>
                        )}
                      </div>
                      <p className="text-gray-300 whitespace-pre-wrap leading-relaxed">{event.description}</p>
                    </TabsContent>

                    <TabsContent value="agenda" className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                      {event.agenda && Array.isArray(event.agenda) && event.agenda.length > 0 ? (
                        <div className="space-y-3">
                          {event.agenda.map((item: any, i: number) => (
                            <div key={i} className="flex gap-4 p-4 rounded-xl bg-white/5 border border-white/10 hover:border-cyan-500/30 transition-colors">
                              {item.startTime && (
                                <div className="flex items-center gap-1.5 text-sm text-cyan-400 font-mono shrink-0 pt-1">
                                  <Clock className="h-3.5 w-3.5" />
                                  {item.startTime}
                                </div>
                              )}
                              <div>
                                <p className="font-bold text-lg">{item.title}</p>
                                {item.speaker && <p className="text-xs text-cyan-400/70 mt-0.5">By {item.speaker}</p>}
                                {item.description && <p className="text-sm text-gray-400 mt-2">{item.description}</p>}
                              </div>
                            </div>
                          ))}
                        </div>
                      ) : (
                        <div className="text-center py-10 text-gray-500 italic">No agenda items listed yet.</div>
                      )}
                    </TabsContent>

                    <TabsContent value="discussion">
                      <EventDiscussionBoard eventId={event._id} />
                    </TabsContent>

                    <TabsContent value="photos">
                      <EventGallery eventId={event._id} isRegistered={isRegistered} />
                    </TabsContent>

                    <TabsContent value="polls">
                      <EventPolls eventId={event._id} isOrganizer={!!isOrganizer} />
                    </TabsContent>
                  </Tabs>
                </div>
              </CardContent>
            </Card>
          </div>
          <div className="space-y-6">
            <Card className="bg-white/5 border-white/10 text-white">
              <CardContent className="p-6">
                <div className="text-center mb-4">
                  <p className="text-3xl font-bold">
                    {appliedDiscount ? (
                      <span className="flex items-center justify-center gap-2">
                        <span className="line-through text-gray-500 text-xl">
                          ${event.price}
                        </span>
                        <span className="text-green-400">
                          ${Math.max(0, (event.price || 0) - (appliedDiscount.type === 'percentage' ? ((event.price || 0) * appliedDiscount.value / 100) : appliedDiscount.value))}
                        </span>
                      </span>
                    ) : (
                      event.isPaid ? `$${event.price}` : 'Free'
                    )}
                  </p>
                </div>

                {/* Discount Code Input */}
                {event.isPaid && !isRegistered && (
                  <div className="mb-4 space-y-2">
                    <div className="flex gap-2">
                      <div className="relative flex-1">
                        <Tag className="absolute left-3 top-1/2 -translate-y-1/2 h-3 w-3 text-gray-400" />
                        <Input 
                          placeholder="Promo code" 
                          value={discountCode}
                          onChange={(e) => setDiscountCode(e.target.value)}
                          className="pl-8 h-9 text-xs bg-white/5 border-white/10"
                        />
                      </div>
                      <Button 
                        size="sm" 
                        variant="outline" 
                        className="h-9 border-white/10"
                        onClick={handleApplyDiscount}
                        disabled={!discountCode || registering}
                      >
                        Apply
                      </Button>
                    </div>
                    {appliedDiscount && (
                      <p className="text-[10px] text-green-400 flex items-center gap-1">
                        <CheckCircle className="h-3 w-3" /> Code applied successfully!
                      </p>
                    )}
                  </div>
                )}

                {/* Capacity mini bar */}
                <div className="mb-4">
                  <div className="flex items-center justify-between text-xs text-gray-400 mb-1">
                    <span>{event.registeredCount} registered</span>
                    <span>{event.capacity} max</span>
                  </div>
                  <Progress value={capacityPercent} className="h-1.5" />
                </div>
                <Button className="w-full" size="lg" onClick={() => handleRegister()} disabled={registering || isRegistered || isFull || event.status === 'cancelled'}>
                  {registering ? <Loader2 className="animate-spin" /> : isRegistered ? <CheckCircle className="mr-2" /> : <Ticket className="mr-2" />}
                  {isRegistered ? 'Registered' : isFull ? 'Sold Out' : 'Register Now'}
                </Button>
                {isRegistered && (new Date().getTime() > event.startDate) && (
                  <Button variant="outline" className="w-full mt-3 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500/10" asChild>
                    <Link href={`/events/${eventId}/feedback`}>
                      <MessageSquare className="mr-2 h-4 w-4" /> Give Feedback
                    </Link>
                  </Button>
                )}
                {event.waitlistEnabled && isFull && !isRegistered && (
                  <p className="text-xs text-center text-gray-400 mt-2">You&apos;ll be added to the waitlist</p>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

            {/* AI Chatbot */}

            {showChatbot ? (

              <div className="fixed bottom-6 right-6 z-50 w-80 md:w-96">

                <EventChatbot 

                  event={{

                    id: event._id,

                    title: event.title,

                    description: event.description,

                    date: new Date(event.startDate).toLocaleDateString(),

                    location: typeof event.location === 'string' ? event.location : event.location?.venue?.name,

                    category: event.category,

                    agenda: event.agenda,

                  } as any}

                  onClose={() => setShowChatbot(false)}

                />

              </div>

            ) : (

              <ChatbotTrigger onClick={() => setShowChatbot(true)} />

            )}

      

            {/* Tier Selection Dialog */}

            <Dialog open={showTierSelection} onOpenChange={setShowTierSelection}>

              <DialogContent className="bg-[#0f172a] border-white/10 text-white max-w-md">

                <DialogHeader>

                  <DialogTitle>Select Ticket Tier</DialogTitle>

                  <DialogDescription className="text-gray-400">

                    Choose the best option for your experience.

                  </DialogDescription>

                </DialogHeader>

                                <div className="space-y-3 py-4">

                                  {/* Discount input inside dialog if not already applied */}

                                  {!appliedDiscount && (

                                     <div className="flex gap-2 mb-4">

                                      <Input 

                                        placeholder="Enter promo code" 

                                        value={discountCode}

                                        onChange={(e) => setDiscountCode(e.target.value)}

                                        className="bg-white/5 border-white/10"

                                      />

                                      <Button onClick={handleApplyDiscount} variant="outline">Apply</Button>

                                    </div>

                                  )}

                                  {appliedDiscount && (

                                    <div className="bg-green-500/10 border border-green-500/20 p-2 rounded-lg flex justify-between items-center mb-4">

                                      <p className="text-xs text-green-400 flex items-center gap-1">

                                        <Tag className="h-3 w-3" /> Code <strong>{discountCode.toUpperCase()}</strong> applied

                                      </p>

                                      <Button variant="ghost" size="sm" className="h-6 text-xs text-gray-400" onClick={() => {setAppliedDiscount(null); setDiscountCode('');}}>Remove</Button>

                                    </div>

                                  )}

                

                                  {event.ticketTiers?.map((tier: any) => {

                                    const isTierFull = tier.registeredCount >= tier.capacity;

                                    

                                    let finalTierPrice = tier.price;

                                    if (appliedDiscount && tier.price > 0) {

                                      const discount = appliedDiscount.type === 'percentage' 

                                        ? (tier.price * appliedDiscount.value / 100) 

                                        : appliedDiscount.value;

                                      finalTierPrice = Math.max(0, tier.price - discount);

                                    }

                

                                    return (

                                      <button

                                        key={tier.name}

                                        disabled={isTierFull}

                                        onClick={() => handleRegister(tier.name)}

                                        className={cn(

                                          "w-full p-4 rounded-xl border transition-all text-left flex justify-between items-center group",

                                          isTierFull 

                                            ? "bg-white/5 border-white/5 opacity-50 cursor-not-allowed" 

                                            : "bg-white/5 border-white/10 hover:border-cyan-500/50 hover:bg-white/[0.08]"

                                        )}

                                      >

                                        <div className="flex-1">

                                          <div className="flex items-center gap-2">

                                            <p className="font-bold text-lg">{tier.name}</p>

                                            {isTierFull && <Badge variant="destructive" className="text-[8px] h-4">SOLD OUT</Badge>}

                                          </div>

                                          {tier.description && <p className="text-xs text-gray-500 mt-1">{tier.description}</p>}

                                          <p className="text-[10px] text-gray-600 mt-2">{tier.capacity - tier.registeredCount} spots remaining</p>

                                        </div>

                                        <div className="text-right ml-4">

                                          <p className="text-xl font-black text-cyan-400">

                                            {appliedDiscount && tier.price > 0 ? (

                                              <span className="flex flex-col items-end">

                                                <span className="text-[10px] line-through text-gray-500">${tier.price}</span>

                                                <span>{finalTierPrice > 0 ? `${finalTierPrice}` : 'FREE'}</span>

                                              </span>

                                            ) : (

                                              tier.price > 0 ? `${tier.price}` : 'FREE'

                                            )}

                                          </p>

                                        </div>

                                      </button>

                                    );

                                  })}

                                </div>

              </DialogContent>

            </Dialog>

          </div>

        );

      }

'use client';
import { useState, useRef } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Textarea } from '@/components/ui/textarea';
import { useStorage } from '@/lib/storage';
import { useAuth } from '@/hooks/use-auth';
import { ImagePlus, Loader2, X } from 'lucide-react';
import type { Event } from '@/types';

const formSchema = z.object({
  title: z.string().min(3),
  date: z.string().min(1),
  time: z.string().min(1),
  location: z.string().min(2),
  category: z.enum(['Workshop', 'Talk', 'Panel', 'Tech', 'Networking', 'Social', 'Career']),
  targetAudience: z.enum(['Student', 'Professional', 'Both']),
  description: z.string().min(10),
  capacity: z.coerce.number().min(1).max(100000),
  status: z.enum(['draft', 'published']),
  type: z.enum(['physical', 'virtual', 'hybrid']),
});

type EventFormProps = {
  onSave: (event: Omit<Event, 'id'>) => Promise<void> | void;
  event: Event | null;
};

function getDateString(event: Event): string {
  if (event.startDate) {
    const date = event.startDate instanceof Date ? event.startDate : new Date(event.startDate);
    return date.toISOString().split('T')[0];
  }
  return '';
}

function getLocationString(event: Event): string {
  if (typeof event.location === 'string') return event.location;
  if (event.location?.venue?.name) return event.location.venue.name;
  return '';
}

export function EventForm({ onSave, event }: EventFormProps) {
  const { user } = useAuth();
//   const { uploadFile } = useStorage();
  const [imageUrl, setImageUrl] = useState<string | null>(event?.imageUrl || null);
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    setUploading(true);
    try {
      const { storageId } = await uploadFile(file, user._id || user.id);
      // Storage URL is returned from saveFile — use the storageId as a reference
      setImageUrl(`/api/storage/${storageId}`);
    } catch {
      // fallback: use object URL for preview
      setImageUrl(URL.createObjectURL(file));
    } finally {
      setUploading(false);
    }
  };

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: event ? {
        title: event.title,
        date: getDateString(event),
        time: event.time || '',
        location: getLocationString(event),
        category: (event.category as z.infer<typeof formSchema>['category']) || 'Workshop',
        targetAudience: (event.targetAudience as 'Student' | 'Professional' | 'Both') || 'Both',
        description: event.description,
        capacity: event.capacity ?? 100,
        status: (event.status as 'draft' | 'published') ?? 'draft',
        type: (event.type as 'physical' | 'virtual' | 'hybrid') ?? 'physical',
    } : {
      title: '',
      date: '',
      time: '',
      location: '',
      category: 'Workshop',
      targetAudience: 'Both',
      description: '',
      capacity: 50,
      status: 'draft',
      type: 'physical',
    },
  });

  function onSubmit(values: z.infer<typeof formSchema>) {
    const startDate = new Date(values.date + 'T' + values.time);
    const eventData: Omit<Event, 'id'> = {
      title: values.title,
      description: values.description,
      startDate: startDate.getTime(),
      endDate: startDate.getTime() + 3600000,
      location: { venue: values.location },
      type: values.type,
      category: values.category,
      capacity: values.capacity,
      status: values.status,
      organizerId: '' as any,
      registeredCount: 0,
      date: values.date,
      time: values.time,
      targetAudience: values.targetAudience,
    };
    if (imageUrl) (eventData as any).imageUrl = imageUrl;
    onSave(eventData);
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
        {/* Image Upload */}
        <div className="space-y-2">
          <label className="text-sm font-medium">Event Image</label>
          <div className="flex items-center gap-4">
            {imageUrl ? (
              <div className="relative w-full h-48 rounded-lg overflow-hidden border border-white/10 bg-white/5">
                <img src={imageUrl} alt="Event" className="w-full h-full object-cover" />
                <Button type="button" size="icon" variant="ghost" className="absolute top-2 right-2 bg-black/50 hover:bg-black/70 h-8 w-8" onClick={() => { setImageUrl(null); if (fileInputRef.current) fileInputRef.current.value = ''; }}>
                  <X className="h-4 w-4" />
                </Button>
              </div>
            ) : (
              <button type="button" onClick={() => fileInputRef.current?.click()} disabled={uploading} className="w-full h-48 rounded-lg border-2 border-dashed border-white/10 hover:border-cyan-500/50 bg-white/5 flex flex-col items-center justify-center gap-2 transition-colors">
                {uploading ? <Loader2 className="h-8 w-8 animate-spin text-cyan-500" /> : <ImagePlus className="h-8 w-8 text-gray-500" />}
                <span className="text-sm text-gray-500">{uploading ? 'Uploading...' : 'Click to upload event image'}</span>
              </button>
            )}
            <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
          </div>
        </div>

        <FormField control={form.control} name="title" render={({ field }) => (<FormItem><FormLabel>Title</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>)}/>
        <div className="grid grid-cols-2 gap-4">
            <FormField control={form.control} name="date" render={({ field }) => (<FormItem><FormLabel>Date</FormLabel><FormControl><Input type="date" {...field} /></FormControl><FormMessage /></FormItem>)}/>
            <FormField control={form.control} name="time" render={({ field }) => (<FormItem><FormLabel>Time</FormLabel><FormControl><Input type="time" {...field} /></FormControl><FormMessage /></FormItem>)}/>
        </div>
        <FormField control={form.control} name="location" render={({ field }) => (<FormItem><FormLabel>Location</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>)}/>
        <div className="grid grid-cols-2 gap-4">
            <FormField control={form.control} name="category" render={({ field }) => (<FormItem><FormLabel>Category</FormLabel><Select onValueChange={field.onChange} defaultValue={field.value}><FormControl><SelectTrigger><SelectValue/></SelectTrigger></FormControl><SelectContent><SelectItem value="Workshop">Workshop</SelectItem><SelectItem value="Talk">Talk</SelectItem><SelectItem value="Panel">Panel</SelectItem><SelectItem value="Tech">Tech</SelectItem><SelectItem value="Networking">Networking</SelectItem><SelectItem value="Social">Social</SelectItem><SelectItem value="Career">Career</SelectItem></SelectContent></Select><FormMessage /></FormItem>)}/>
            <FormField control={form.control} name="targetAudience" render={({ field }) => (<FormItem><FormLabel>Target Audience</FormLabel><Select onValueChange={field.onChange} defaultValue={field.value}><FormControl><SelectTrigger><SelectValue/></SelectTrigger></FormControl><SelectContent><SelectItem value="Student">Student</SelectItem><SelectItem value="Professional">Professional</SelectItem><SelectItem value="Both">Both</SelectItem></SelectContent></Select><FormMessage /></FormItem>)}/>
        </div>
        <div className="grid grid-cols-3 gap-4">
            <FormField control={form.control} name="capacity" render={({ field }) => (<FormItem><FormLabel>Capacity</FormLabel><FormControl><Input type="number" min={1} {...field} /></FormControl><FormMessage /></FormItem>)}/>
            <FormField control={form.control} name="status" render={({ field }) => (<FormItem><FormLabel>Status</FormLabel><Select onValueChange={field.onChange} defaultValue={field.value}><FormControl><SelectTrigger><SelectValue/></SelectTrigger></FormControl><SelectContent><SelectItem value="draft">Draft</SelectItem><SelectItem value="published">Published</SelectItem></SelectContent></Select><FormMessage /></FormItem>)}/>
            <FormField control={form.control} name="type" render={({ field }) => (<FormItem><FormLabel>Event Type</FormLabel><Select onValueChange={field.onChange} defaultValue={field.value}><FormControl><SelectTrigger><SelectValue/></SelectTrigger></FormControl><SelectContent><SelectItem value="physical">In-Person</SelectItem><SelectItem value="virtual">Virtual</SelectItem><SelectItem value="hybrid">Hybrid</SelectItem></SelectContent></Select><FormMessage /></FormItem>)}/>
        </div>
        <FormField control={form.control} name="description" render={({ field }) => (<FormItem><FormLabel>Description</FormLabel><FormControl><Textarea {...field} /></FormControl><FormMessage /></FormItem>)}/>
        <Button type="submit" className="w-full">Save Event</Button>
      </form>
    </Form>
  );
}

'use client';
// 
// import { useState, useRef } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { 
  Image as ImageIcon, 
  Plus, 
  X, 
  Loader2, 
  Camera, 
  Trash2, 
  Maximize2,
  Download
} from 'lucide-react';
import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Dialog, DialogContent, DialogTrigger } from '@/components/ui/dialog';

interface EventGalleryProps {
  eventId: Id<"events">;
  isRegistered: boolean;
}

export function EventGallery({ eventId, isRegistered }: EventGalleryProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);
//   

  const [uploading, setUploading] = useState(false);
  const [selectedPhoto, setSelectedPhoto] = useState<any>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      toast({ title: "Invalid file", description: "Please upload an image.", variant: "destructive" });
      return;
    }

    setUploading(true);
    try {
      const postUrl = await generateUploadUrl();
      const result = await fetch(postUrl, {
        method: "POST",
        headers: { "Content-Type": file.type },
        body: file,
      });
      const { storageId } = await result.json();
      
      await uploadPhoto({
        eventId,
        storageId,
        caption: ""
      });

      toast({ title: "Photo shared!" });
    } catch (error) {
      toast({ title: "Upload failed", variant: "destructive" });
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white">Event Gallery</h2>
          <p className="text-sm text-gray-500">Shared moments from the event.</p>
        </div>
        {isRegistered && (
          <div className="flex items-center gap-3">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*"
              onChange={handleFileUpload} 
            />
            <Button 
              onClick={() => fileInputRef.current?.click()} 
              disabled={uploading}
              className="bg-cyan-600 hover:bg-cyan-500 text-white rounded-full"
            >
              {uploading ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Plus className="w-4 h-4 mr-2" />}
              Share Photo
            </Button>
          </div>
        )}
      </div>

      {photos.length === 0 ? (
        <div className="py-32 text-center border border-dashed border-white/10 rounded-3xl bg-white/5">
          <Camera size={48} className="mx-auto mb-4 text-gray-700 opacity-20" />
          <h3 className="text-lg font-bold text-gray-500">No photos yet</h3>
          <p className="text-sm text-gray-600">Be the first to share a moment!</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {photos.map((photo) => (
            <div 
              key={photo._id} 
              className="relative aspect-square rounded-2xl overflow-hidden group cursor-pointer border border-white/5"
              onClick={() => setSelectedPhoto(photo)}
            >
              <img 
                src={photo.imageUrl} 
                alt="event" 
                className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
              />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                <Maximize2 className="text-white w-6 h-6" />
              </div>
              <div className="absolute bottom-0 left-0 right-0 p-3 bg-gradient-to-t from-black/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
                <div className="flex items-center gap-2">
                  <Avatar className="h-5 w-5">
                    <AvatarImage src={photo.authorImage} />
                    <AvatarFallback className="text-[8px] bg-cyan-500/20 text-cyan-400">
                      {photo.authorName[0]}
                    </AvatarFallback>
                  </Avatar>
                  <span className="text-[10px] text-white font-medium truncate">{photo.authorName}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Lightbox */}
      <Dialog open={!!selectedPhoto} onOpenChange={() => setSelectedPhoto(null)}>
        <DialogContent className="max-w-4xl p-0 bg-black/90 border-white/10 overflow-hidden">
          {selectedPhoto && (
            <div className="relative flex flex-col md:flex-row h-full max-h-[80vh]">
              <div className="flex-1 bg-black flex items-center justify-center p-4">
                <img 
                  src={selectedPhoto.imageUrl} 
                  alt="full view" 
                  className="max-w-full max-h-full object-contain"
                />
              </div>
              <div className="w-full md:w-80 bg-gray-900 p-6 flex flex-col justify-between">
                <div className="space-y-6">
                  <div className="flex items-center gap-3">
                    <Avatar>
                      <AvatarImage src={selectedPhoto.authorImage} />
                      <AvatarFallback className="bg-cyan-500/20 text-cyan-400">{selectedPhoto.authorName[0]}</AvatarFallback>
                    </Avatar>
                    <div>
                      <p className="font-bold text-white">{selectedPhoto.authorName}</p>
                      <p className="text-xs text-gray-500">Shared on {new Date(selectedPhoto.createdAt).toLocaleDateString()}</p>
                    </div>
                  </div>
                  {selectedPhoto.caption && <p className="text-sm text-gray-300 italic">"{selectedPhoto.caption}"</p>}
                </div>
                
                <div className="flex gap-2 mt-10">
                  <Button variant="outline" className="flex-1 border-white/10" asChild>
                    <a href={selectedPhoto.imageUrl} download target="_blank">
                      <Download className="w-4 h-4 mr-2" /> Download
                    </a>
                  </Button>
                  {(user?._id === selectedPhoto.userId) && (
                    <Button 
                      variant="ghost" 
                      className="text-red-400 hover:text-red-300 hover:bg-red-400/10"
                      onClick={async () => {
                        await deletePhoto({ id: selectedPhoto._id });
                        setSelectedPhoto(null);
                        toast({ title: "Photo deleted" });
                      }}
                    >
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  )}
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';
// 
