import { getAIRecommendations, AIRecommendation } from '@/app/actions/ai-recommendations';
import { cn } from '@/core/utils/utils';
import type { Event } from '@/types';
import { getUserInterests, getUserSkills, getUserAttendedEvents } from '@/types';

const categories = [
  'All',
  'Tech',
  'Workshop',
  'Networking',
  'Social',
  'Career',
  'Academic',
  'Sports',
  'Arts',
  'Music',
];

const dateFilters = [
  { label: 'Any time', value: 'all' },
  { label: 'Today', value: 'today' },
  { label: 'This week', value: 'week' },
  { label: 'This month', value: 'month' },
  { label: 'This year', value: 'year' },
];

const sortOptions = [
  { label: 'Latest', value: 'date-desc' },
  { label: 'Soonest', value: 'date-asc' },
];

export default function ExploreClient() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const observerRef = useRef<IntersectionObserver | null>(null);
  const loadMoreRef = useRef<HTMLDivElement>(null);
  const { user } = useAuth();

  // Filters
  const [searchQuery, setSearchQuery] = useState(searchParams.get('q') || '');
  const [selectedCategory, setSelectedCategory] = useState(searchParams.get('category') || 'All');
  const [dateFilter, setDateFilter] = useState(searchParams.get('date') || 'all');
  const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'date-desc');
  const [locationFilter, setLocationFilter] = useState(searchParams.get('location') || '');
  const [showOnlyFree, setShowOnlyFree] = useState(false);

//     { status: "published" },
//     { initialNumItems: 12 }
//   );

  // State
  const [filteredEvents, setFilteredEvents] = useState<Event[]>([]);
  
  // AI Recommendations state
  const [aiRecommendations, setAiRecommendations] = useState<AIRecommendation[]>([]);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsights, setAiInsights] = useState<{ weeklyPlan?: string; learningPath?: string[] } | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  
  const ITEMS_PER_PAGE = 12;

  const events: Event[] = useMemo(() => (paginatedEvents || []).map((e: any) => ({
    ...e,
    id: e._id,
  })), [paginatedEvents]);

  // Fetch AI Recommendations when events are loaded
  const fetchAIRecommendations = useCallback(async () => {
    if (events.length === 0) return;
    
    setAiLoading(true);
    setAiError(null);
    
    try {
      const userInterests = getUserInterests(user) || ['Tech', 'Networking', 'Career'];
      const userSkills = getUserSkills(user) || ['networking', 'learning'];
      const pastEventTypes = getUserAttendedEvents(user).slice(0, 5).map(() => 'Workshop');
      
      const result = await getAIRecommendations(
        user?._id || user?.id || 'guest',
        userInterests,
        userSkills,
        pastEventTypes,
        events
      );
      
      setAiRecommendations(result.recommendations);
      setAiInsights(result.insights || null);
      if (result.error) setAiError(result.error);
    } catch (error) {
      console.error('Failed to fetch AI recommendations:', error);
      setAiError('Unable to load personalized recommendations');
    } finally {
      setAiLoading(false);
    }
  }, [events, user]);

  useEffect(() => {
    if (events.length > 0 && aiRecommendations.length === 0) {
      fetchAIRecommendations();
    }
  }, [events, fetchAIRecommendations, aiRecommendations.length]);

  const displayedEvents = useMemo(() => {
    let result = [...events];

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      result = result.filter(event => 
        event.title.toLowerCase().includes(query) ||
        event.description.toLowerCase().includes(query) ||
        event.category.toLowerCase().includes(query)
      );
    }

    if (selectedCategory && selectedCategory !== 'All') {
      result = result.filter(event => event.category === selectedCategory);
    }

    // ... (rest of the filtering logic remains same but simplified for the paginated context)
    return result;
  }, [events, searchQuery, selectedCategory]);

  const handleLoadMore = () => {
    if (status === "CanLoadMore") {
      loadMore(ITEMS_PER_PAGE);
    }
  };

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && status === "CanLoadMore") {
          handleLoadMore();
        }
      },
      { threshold: 0.1 }
    );

    if (loadMoreRef.current) {
      observer.observe(loadMoreRef.current);
    }

    return () => observer.disconnect();
  }, [status]);
  const activeFiltersCount = [
    selectedCategory !== 'All',
    dateFilter !== 'all',
    showOnlyFree,
    locationFilter,
  ].filter(Boolean).length;

  const clearFilters = () => {
    setSelectedCategory('All');
    setDateFilter('all');
    setShowOnlyFree(false);
    setLocationFilter('');
    setSearchQuery('');
  };

  const featuredEvent = events
    .filter(e => {
      const eventDate = e.startDate ? new Date(e.startDate) : new Date(e.date || '');
      return eventDate > new Date();
    })
    .sort((a, b) => ((b.registeredCount || 0) - (a.registeredCount || 0)))[0];

  return (
    <div className="min-h-screen bg-black">
      <section className="relative pt-32 pb-16">
        <div className="absolute inset-0">
          <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-purple-500/20 rounded-full blur-[120px]" />
          <div className="absolute top-1/3 right-1/4 w-[400px] h-[400px] bg-blue-500/15 rounded-full blur-[100px]" />
        </div>
        
        <div className="max-w-7xl mx-auto px-6 relative">
          <div className="max-w-3xl mx-auto text-center mb-12">
            <Badge className="mb-6 px-4 py-2 bg-white/10 border-white/20 text-white backdrop-blur-sm">
              <Sparkles className="w-4 h-4 mr-2 text-purple-400" /> Discover Amazing Events
            </Badge>
            <h1 className="text-5xl md:text-6xl font-bold mb-6">
              <span className="text-white">Explore </span>
              <span className="bg-gradient-to-r from-purple-400 via-pink-400 to-blue-400 bg-clip-text text-transparent">Events</span>
            </h1>
          </div>

          <div className="max-w-2xl mx-auto">
            <div className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-purple-600 to-pink-600 rounded-2xl blur opacity-25 group-hover:opacity-40 transition-opacity" />
              <div className="relative flex items-center bg-white/10 backdrop-blur-xl rounded-2xl border border-white/20 p-2">
                <Search className="w-5 h-5 text-gray-400 ml-4" />
                <Input
                  placeholder="Search events, categories, locations..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="flex-1 bg-transparent border-0 text-white placeholder:text-gray-500 focus-visible:ring-0 text-lg h-12"
                />
                {searchQuery && (
                  <Button variant="ghost" size="icon" className="text-gray-400 hover:text-white mr-2" onClick={() => setSearchQuery('')}>
                    <X className="h-4 w-4" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="max-w-7xl mx-auto px-6 py-8">
        <div className="flex items-center gap-2 overflow-x-auto pb-6 scrollbar-hide">
          {categories.map((category) => (
            <Button
              key={category}
              variant="ghost"
              size="sm"
              className={cn(
                "rounded-full whitespace-nowrap px-5 py-2 transition-all duration-300",
                selectedCategory === category 
                  ? "bg-gradient-to-r from-purple-600 to-pink-600 text-white" 
                  : "bg-white/5 text-gray-400 hover:bg-white/10 hover:text-white border border-white/10"
              )}
              onClick={() => setSelectedCategory(category)}
            >
              {category}
            </Button>
          ))}
        </div>

        <div className="flex flex-wrap items-center justify-between gap-4 py-4 border-b border-white/10 mb-8">
          <div className="flex items-center gap-3">
            <Select value={dateFilter} onValueChange={setDateFilter}>
              <SelectTrigger className="w-[140px] bg-white/5 border-white/10 text-white rounded-xl">
                <Calendar className="h-4 w-4 mr-2 text-gray-400" /> <SelectValue />
              </SelectTrigger>
              <SelectContent className="bg-black/90 border-white/10">
                {dateFilters.map((filter) => (
                  <SelectItem key={filter.value} value={filter.value} className="text-gray-300">{filter.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select value={sortBy} onValueChange={setSortBy}>
              <SelectTrigger className="w-[160px] bg-white/5 border-white/10 text-white rounded-xl">
                <SelectValue />
              </SelectTrigger>
              <SelectContent className="bg-black/90 border-white/10">
                {sortOptions.map((option) => (
                  <SelectItem key={option.value} value={option.value} className="text-gray-300">{option.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Sheet>
              <SheetTrigger asChild>
                <Button variant="outline" className="bg-white/5 border-white/10 text-white rounded-xl">
                  <SlidersHorizontal className="h-4 w-4 mr-2" /> Filters
                  {activeFiltersCount > 0 && <Badge className="ml-1 bg-purple-500">{activeFiltersCount}</Badge>}
                </Button>
              </SheetTrigger>
              <SheetContent className="bg-black/95 border-white/10 text-white">
                <SheetHeader><SheetTitle className="text-white">Filter Events</SheetTitle></SheetHeader>
                <div className="py-6 space-y-6">
                  <div>
                    <label className="text-sm font-medium mb-2 block">Location</label>
                    <div className="relative">
                      <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                      <Input
                        placeholder="Filter by location..."
                        value={locationFilter}
                        onChange={(e) => setLocationFilter(e.target.value)}
                        className="pl-9 bg-white/5 border-white/10 text-white"
                      />
                    </div>
                  </div>
                  <div className="flex items-center justify-between p-4 bg-white/5 rounded-xl border border-white/10">
                    <p>Free Events Only</p>
                    <Button
                      variant={showOnlyFree ? 'default' : 'outline'}
                      size="sm"
                      onClick={() => setShowOnlyFree(!showOnlyFree)}
                      className={showOnlyFree ? "bg-purple-600" : ""}
                    >
                      {showOnlyFree ? 'On' : 'Off'}
                    </Button>
                  </div>
                  {activeFiltersCount > 0 && <Button variant="outline" className="w-full text-white" onClick={clearFilters}>Clear All</Button>}
                </div>
              </SheetContent>
            </Sheet>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-400">{events.length} events loaded</span>
            <div className="flex items-center bg-white/5 border border-white/10 rounded-xl p-1">
              <Button
                variant="ghost"
                size="icon"
                className={cn("h-8 w-8", viewMode === 'grid' ? "bg-white/10 text-white" : "text-gray-400")}
                onClick={() => setViewMode('grid')}
              >
                <Grid3X3 className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className={cn("h-8 w-8", viewMode === 'list' ? "bg-white/10 text-white" : "text-gray-400")}
                onClick={() => setViewMode('list')}
              >
                <List className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-purple-500" /></div>
        ) : (
          <>
            {featuredEvent && !searchQuery && selectedCategory === 'All' && (
              <div className="mb-10">
                <h2 className="text-2xl font-bold mb-6 flex items-center gap-3 text-white">
                  <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  Featured Event
                </h2>
                <EventCard event={featuredEvent} variant="featured" />
              </div>
            )}

            {!searchQuery && selectedCategory === 'All' && events.length > 4 && (
              <div className="mb-10">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-3 text-white">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-cyan-500 flex items-center justify-center"><Brain className="h-5 w-5 text-white" /></div>
                    Recommended For You
                  </h2>
                  <div className="flex items-center gap-2">
                    <Badge className="bg-purple-600/20 text-purple-300 border border-purple-500/30">AI Powered</Badge>
                    <Button variant="ghost" size="icon" onClick={fetchAIRecommendations} disabled={aiLoading}><RefreshCw className={cn("h-4 w-4", aiLoading && "animate-spin")} /></Button>
                  </div>
                </div>
                
                {aiLoading ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {[1, 2, 3, 4].map((i) => <div key={i} className="h-[300px] rounded-2xl bg-white/5 animate-pulse" />)}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {aiRecommendations.slice(0, 4).map((rec) => {
                      const event = events.find(e => e.id === rec.eventId);
                      if (!event) return null;
                      return <EventCard key={event.id} event={event} variant="default" />;
                    })}
                  </div>
                )}
              </div>
            )}

                        {displayedEvents.length === 0 && status !== "LoadingFirstPage" ? (

                          <div className="flex flex-col items-center justify-center py-20 bg-white/5 border border-white/10 rounded-3xl">

                            <Search className="h-16 w-16 text-gray-600 mb-6" />

                            <h3 className="text-2xl font-bold text-white mb-2">No events found</h3>

                            <Button variant="outline" className="border-white/20 text-white mt-6" onClick={clearFilters}>Clear Filters</Button>

                          </div>

                        ) : (

                          <div className={cn(viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6" : "space-y-4")}>

                            {displayedEvents.map((event) => <EventCard key={event.id} event={event} variant={viewMode === 'list' ? 'compact' : 'default'} />)}

                          </div>

                        )}

                        

                        {(status === "CanLoadMore" || status === "LoadingMore") && (

                          <div ref={loadMoreRef} className="flex justify-center py-10">

                            <Loader2 className="h-6 w-6 animate-spin text-purple-500" />

                          </div>

                        )}

                      </>

                    )}

                  </section>

                </div>

              );

            }

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { 
  Calendar, 
  MapPin, 
  QrCode, 
  Navigation,
  Clock,
  Star,
  X,
  Download,
  ExternalLink
} from 'lucide-react';
import { cn } from '@/core/utils/utils';
import type { Event } from '@/types';
import { format, isPast, isFuture, isToday, differenceInHours, differenceInMinutes } from 'date-fns';

interface MyEventCardProps {
  event: Event;
  variant?: 'upcoming' | 'past' | 'wishlist';
  onRemoveWishlist?: (eventId: string) => void;
  onRate?: (eventId: string, rating: number) => void;
}

export function MyEventCard({ 
  event, 
  variant = 'upcoming',
  onRemoveWishlist,
  onRate
}: MyEventCardProps) {
  const [rating, setRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);

  const parseDate = (dateVal: any): Date => {
    if (!dateVal) return new Date();
    if (dateVal instanceof Date) return dateVal;
    if (typeof dateVal === 'number') return new Date(dateVal);
    if (typeof dateVal === 'string') return new Date(dateVal);
    // Legacy support for Firestore-like objects
    if (typeof dateVal === 'object' && 'toDate' in dateVal && typeof dateVal.toDate === 'function') {
      return dateVal.toDate();
    }
    return new Date(dateVal);
  };

  const displayDate = parseDate(event.startDate);

  const eventImage = event.imageUrl || event.image || `https://picsum.photos/seed/${event.id}/800/600`;

  // Get live status
  const getLiveStatus = () => {
    const now = new Date();
    const eventDate = displayDate;
    const endDate = event.endDate ? parseDate(event.endDate) : new Date(eventDate.getTime() + 3 * 60 * 60 * 1000); // Default 3 hours

    // Event is live now
    if (now >= eventDate && now <= endDate) {
      return {
        label: 'Live Now',
        variant: 'default' as const,
        className: 'bg-red-500 text-white animate-pulse',
        icon: 'ðŸ”´'
      };
    }

    // Event ended
    if (isPast(endDate)) {
      return {
        label: 'Ended',
        variant: 'secondary' as const,
        className: 'bg-muted',
        icon: null
      };
    }

    // Event starts soon
    const hoursUntil = differenceInHours(eventDate, now);
    const minutesUntil = differenceInMinutes(eventDate, now);

    if (minutesUntil < 60) {
      return {
        label: `Starts in ${minutesUntil}m`,
        variant: 'default' as const,
        className: 'bg-orange-500 text-white',
        icon: 'â°'
      };
    } else if (hoursUntil < 24) {
      return {
        label: `Starts in ${hoursUntil}h`,
        variant: 'default' as const,
        className: 'bg-[hsl(var(--primary))]',
        icon: 'â°'
      };
    } else if (hoursUntil < 72) {
      const days = Math.floor(hoursUntil / 24);
      return {
        label: `In ${days} day${days > 1 ? 's' : ''}`,
        variant: 'outline' as const,
        className: '',
        icon: null
      };
    }

    return null;
  };

  const liveStatus = variant === 'upcoming' ? getLiveStatus() : null;

  const handleRating = (stars: number) => {
    setRating(stars);
    onRate?.(event.id, stars);
  };

  const getGoogleMapsUrl = () => {
    if (event.location?.venue?.name) {
      const address = event.location.venue.address || event.location.venue.name;
      return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
    }
    return null;
  };

  return (
    <Card className="group overflow-hidden hover:shadow-lg transition-all duration-300">
      <div className="relative">
        {/* Event Image */}
        <div className="aspect-video relative overflow-hidden bg-muted">
          <img 
            src={eventImage}
            alt={event.title}
            className="object-cover w-full h-full group-hover:scale-105 transition-transform duration-300"
          />
          {/* Live Status Badge */}
          {liveStatus && (
            <div className="absolute top-3 left-3">
              <Badge className={cn('font-semibold', liveStatus.className)}>
                {liveStatus.icon && <span className="mr-1">{liveStatus.icon}</span>}
                {liveStatus.label}
              </Badge>
            </div>
          )}
          {/* Wishlist Remove Button */}
          {variant === 'wishlist' && (
            <Button
              size="icon"
              variant="secondary"
              className="absolute top-3 right-3 h-8 w-8 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
              onClick={(e) => {
                e.preventDefault();
                onRemoveWishlist?.(event.id);
              }}
            >
              <X className="h-4 w-4" />
            </Button>
          )}
          {/* Category Badge */}
          {event.category && (
            <div className="absolute bottom-3 left-3">
              <Badge variant="secondary" className="backdrop-blur-sm bg-background/80">
                {event.category}
              </Badge>
            </div>
          )}
        </div>
      </div>

      <CardContent className="p-4 space-y-3">
        {/* Event Title */}
        <Link href={`/events/${event.id}`} className="block group-hover:text-primary transition-colors">
          <h3 className="font-semibold text-lg line-clamp-2 mb-1">
            {event.title}
          </h3>
        </Link>

        {/* Date & Time */}
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <Calendar className="h-4 w-4 flex-shrink-0" />
          <span>{format(displayDate, 'EEE, MMM d, yyyy Â· h:mm a')}</span>
        </div>

        {/* Location */}
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <MapPin className="h-4 w-4 flex-shrink-0" />
          <span className="line-clamp-1">
            {event.location?.venue?.name || 
             (event.location?.isVirtual ? 'Virtual Event' : 'Location TBD')}
          </span>
        </div>

        {/* Rating (Past Events Only) */}
        {variant === 'past' && (
          <div className="flex items-center gap-2 pt-2">
            <span className="text-sm text-muted-foreground">Rate:</span>
            <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                <button
                  key={star}
                  onClick={() => handleRating(star)}
                  onMouseEnter={() => setHoverRating(star)}
                  onMouseLeave={() => setHoverRating(0)}
                  className="transition-transform hover:scale-110"
                >
                  <Star 
                    className={cn(
                      "h-5 w-5",
                      (hoverRating >= star || rating >= star)
                        ? "fill-yellow-400 text-yellow-400"
                        : "text-muted-foreground"
                    )}
                  />
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Quick Actions */}
        <div className="flex gap-2 pt-2">
          {variant === 'upcoming' && (
            <>
              <Button asChild size="sm" className="flex-1">
                <Link href={`/tickets?event=${event.id}`}>
                  <QrCode className="h-4 w-4 mr-1" />
                  View Ticket
                </Link>
              </Button>
              {getGoogleMapsUrl() && (
                <Button 
                  asChild
                  size="sm" 
                  variant="outline"
                >
                  <a 
                    href={getGoogleMapsUrl()!} 
                    target="_blank" 
                    rel="noopener noreferrer"
                  >
                    <Navigation className="h-4 w-4" />
                  </a>
                </Button>
              )}
            </>
          )}

          {variant === 'past' && (
            <>
              <Button asChild size="sm" variant="outline" className="flex-1">
                <Link href={`/certificates/${event.id}`}>
                  <Download className="h-4 w-4 mr-1" />
                  Certificate
                </Link>
              </Button>
              <Button asChild size="sm" variant="outline" className="flex-1">
                <Link href={`/events/${event.id}#photos`}>
                  View Photos
                </Link>
              </Button>
            </>
          )}

          {variant === 'wishlist' && (
            <>
              <Button asChild size="sm" className="flex-1">
                <Link href={`/events/${event.id}`}>
                  Register Now
                </Link>
              </Button>
              <Button asChild size="sm" variant="outline">
                <Link href={`/events/${event.id}`}>
                  <ExternalLink className="h-4 w-4" />
                </Link>
              </Button>
            </>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

'use client';

import React, { useState } from 'react';
// import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
// import { Button } from '@/components/ui/button';
// import { 
//   Download, 
//   FileText, 
//   Table as TableIcon, 
//   FileJson,
//   Calendar,
//   Ticket,
//   Users,
//   Loader2
// } from 'lucide-react';
import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';

export default function ExportFunctionality() {
  const { user } = useAuth();
  const { toast } = useToast();
  const [exporting, setExporting] = useState<string | null>(null);
  const myEvents: any[] = [];
  const myTickets: any[] = [];

  const downloadFile = (content: string, fileName: string, contentType: string) => {
    const blob = new Blob([content], { type: contentType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportEvents = (format: 'csv' | 'json') => {
    setExporting('events');
    try {
      if (format === 'json') {
        downloadFile(JSON.stringify(myEvents, null, 2), 'my-events.json', 'application/json');
      } else {
        const headers = ['Title', 'Category', 'Date', 'Type', 'Capacity', 'Registered'];
        const csvContent = [
          headers.join(','),
          ...myEvents.map((e: any) => [
            `"${e.title}"`,
            e.category,
            new Date(e.startDate).toLocaleDateString(),
            e.type,
            e.capacity,
            e.registeredCount
          ].join(','))
        ].join('\n');
        downloadFile(csvContent, 'my-events.csv', 'text/csv');
      }
      toast({ title: 'Export successful' });
    } catch (e) {
      toast({ title: 'Export failed', variant: 'destructive' });
    } finally {
      setExporting(null);
    }
  };

  const exportTickets = (format: 'csv' | 'json') => {
    setExporting('tickets');
    try {
      if (format === 'json') {
        downloadFile(JSON.stringify(myTickets, null, 2), 'my-tickets.json', 'application/json');
      } else {
        const headers = ['Event', 'Ticket Number', 'Status', 'Purchase Date', 'Price'];
        const csvContent = [
          headers.join(','),
          ...myTickets.map((t: any) => [
            `"${t.event?.title || 'Unknown'}"`,
            t.ticketNumber,
            t.status,
            new Date(t.purchaseDate).toLocaleDateString(),
            t.price
          ].join(','))
        ].join('\n');
        downloadFile(csvContent, 'my-tickets.csv', 'text/csv');
      }
      toast({ title: 'Export successful' });
    } catch (e) {
      toast({ title: 'Export failed', variant: 'destructive' });
    } finally {
      setExporting(null);
    }
  };

  return (
    <div className="space-y-8 text-white max-w-4xl mx-auto">
      <div>
        <h1 className="text-4xl font-extrabold tracking-tight">Data Export</h1>
        <p className="text-gray-400 mt-2 text-lg">Download your personal and event data in various formats.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Events Export */}
        <Card className="bg-white/5 border-white/10 text-white overflow-hidden group hover:border-cyan-500/30 transition-all">
          <CardHeader className="pb-4">
            <div className="bg-cyan-500/10 w-12 h-12 rounded-2xl flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
              <Calendar className="text-cyan-400" />
            </div>
            <CardTitle>My Events</CardTitle>
            <CardDescription className="text-gray-500">Events you've organized and managed</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between text-sm py-2 border-b border-white/5">
              <span className="text-gray-400">Total Records</span>
              <span className="font-bold">{myEvents.length}</span>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <Button variant="outline" size="sm" onClick={() => exportEvents('csv')} disabled={exporting === 'events' || myEvents.length === 0} className="border-white/10 hover:bg-white/5">
                <TableIcon className="w-4 h-4 mr-2" /> CSV
              </Button>
              <Button variant="outline" size="sm" onClick={() => exportEvents('json')} disabled={exporting === 'events' || myEvents.length === 0} className="border-white/10 hover:bg-white/5">
                <FileJson className="w-4 h-4 mr-2" /> JSON
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Tickets Export */}
        <Card className="bg-white/5 border-white/10 text-white overflow-hidden group hover:border-purple-500/30 transition-all">
          <CardHeader className="pb-4">
            <div className="bg-purple-500/10 w-12 h-12 rounded-2xl flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
              <Ticket className="text-purple-400" />
            </div>
            <CardTitle>My Tickets</CardTitle>
            <CardDescription className="text-gray-500">Your registration and ticket history</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between text-sm py-2 border-b border-white/5">
              <span className="text-gray-400">Total Records</span>
              <span className="font-bold">{myTickets.length}</span>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <Button variant="outline" size="sm" onClick={() => exportTickets('csv')} disabled={exporting === 'tickets' || myTickets.length === 0} className="border-white/10 hover:bg-white/5">
                <TableIcon className="w-4 h-4 mr-2" /> CSV
              </Button>
              <Button variant="outline" size="sm" onClick={() => exportTickets('json')} disabled={exporting === 'tickets' || myTickets.length === 0} className="border-white/10 hover:bg-white/5">
                <FileJson className="w-4 h-4 mr-2" /> JSON
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card className="bg-gradient-to-br from-gray-900 to-black border-white/5">
        <CardContent className="p-8 text-center space-y-4">
          <FileText size={48} className="mx-auto text-gray-700" />
          <h3 className="text-xl font-bold">Need a full account backup?</h3>
          <p className="text-gray-500 max-w-md mx-auto">Our upcoming "Full Archive" feature will allow you to download all your data, including chat history and community posts, in a single ZIP file.</p>
          <Button variant="link" className="text-cyan-400">Request account archive</Button>
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Plus, Heart, MessageCircle, Share2, Loader2, Search, MoreVertical, Edit2, Trash2 } from 'lucide-react';
import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/core/utils/utils';
import { CommentSection } from './comment-section';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

export default function FeedClient() {
  const { user } = useAuth();
  const { toast } = useToast();

  const communities: any[] = [];
  const createPostMutation = async (data: any) => {};
  const updatePostMutation = async (data: any) => {};
  const deletePostMutation = async (data: any) => {};
  const likePostMutation = async (data: any) => {};
  
  const [showCreatePost, setShowCreatePost] = useState(false);
  const [showEditPost, setShowEditPost] = useState(false);
  const [editingPost, setEditingPost] = useState<any>(null);
  const [newPostContent, setNewPostContent] = useState('');
  const [editPostContent, setEditPostContent] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedComments, setExpandedComments] = useState<Record<string, boolean>>({});

  const toggleComments = (postId: string) => {
    setExpandedComments(prev => ({ ...prev, [postId]: !prev[postId] }));
  };

  const handleCreatePost = async () => {
    if (!newPostContent.trim()) return;
    setLoading(true);
    try {
      // Note: This requires a communityId. For the global feed, we'll use a default community if needed,
      // but usually the feed is scoped. For now, assuming first community or platform feed.
      const defaultCommunityId = communities?.[0]?._id;
      
      if (!defaultCommunityId) throw new Error("No community found to post to");

      await createPostMutation({ content: newPostContent, communityId: defaultCommunityId });
      setShowCreatePost(false);
      setNewPostContent('');
      toast({ title: 'Posted successfully' });
    } catch (e: any) {
      toast({ title: 'Failed to post', description: e.message, variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  const handleUpdatePost = async () => {
    if (!editPostContent.trim() || !editingPost) return;
    setLoading(true);
    try {
      await updatePostMutation({ id: editingPost._id, content: editPostContent });
      setShowEditPost(false);
      setEditingPost(null);
      toast({ title: 'Post updated' });
    } catch (e: any) {
      toast({ title: 'Update failed', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  const handleDeletePost = async (id: string) => {
    if (!confirm('Are you sure you want to delete this post?')) return;
    try {
      await deletePostMutation({ id: id as any });
      toast({ title: 'Post deleted' });
    } catch (e) {
      toast({ title: 'Delete failed', variant: 'destructive' });
    }
  };

  const handleLike = async (id: string) => {
    try {
      await likePostMutation({ id: id as any });
    } catch (e) {}
  };

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl text-white">
      <Card className="mb-6 bg-white/5 border-white/10 text-white">
        <CardContent className="p-4 flex gap-3">
          <Avatar><AvatarFallback>{user?.name?.charAt(0) || 'U'}</AvatarFallback></Avatar>
          <Button variant="outline" className="flex-1 justify-start text-gray-400 border-white/10" onClick={() => setShowCreatePost(true)}>What&apos;s happening?</Button>
        </CardContent>
      </Card>

      <div className="space-y-4">
        {postsRaw.map((post: any) => (
          <Card key={post._id} className="bg-white/5 border-white/10 text-white">
            <CardContent className="p-6">
              <div className="flex justify-between items-start mb-4">
                <div className="flex gap-3">
                  <Avatar>
                    <AvatarImage src={post.authorImage} />
                    <AvatarFallback>{post.authorName?.charAt(0) || 'U'}</AvatarFallback>
                  </Avatar>
                  <div>
                    <p className="font-bold">{post.authorName || 'User'}</p>
                    <p className="text-xs text-gray-500">{new Date(post.createdAt).toLocaleDateString()}</p>
                  </div>
                </div>

                {user?._id === post.authorId && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-white/10">
                        <MoreVertical size={16} />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent className="bg-gray-900 border-white/10 text-white">
                      <DropdownMenuItem 
                        onClick={() => {
                          setEditingPost(post);
                          setEditPostContent(post.content);
                          setShowEditPost(true);
                        }}
                        className="cursor-pointer"
                      >
                        <Edit2 className="w-4 h-4 mr-2" /> Edit
                      </DropdownMenuItem>
                      <DropdownMenuItem 
                        onClick={() => handleDeletePost(post._id)}
                        className="cursor-pointer text-red-400 focus:text-red-400 focus:bg-red-400/10"
                      >
                        <Trash2 className="w-4 h-4 mr-2" /> Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                )}
              </div>
              <p className="text-gray-200 whitespace-pre-wrap">{post.content}</p>
              <div className="flex gap-6 mt-6 pt-4 border-t border-white/10">
                <Button 
                  variant="ghost" 
                  size="sm" 
                  onClick={() => handleLike(post._id)} 
                  className={cn("gap-2 hover:bg-pink-500/10 hover:text-pink-400", post.meLiked && "text-pink-500")}
                >
                  <Heart size={16} fill={post.meLiked ? "currentColor" : "none"} /> {post.likes}
                </Button>
                <Button 
                  variant="ghost" 
                  size="sm" 
                  onClick={() => toggleComments(post._id)}
                  className={cn("gap-2 hover:bg-cyan-500/10 hover:text-cyan-400", expandedComments[post._id] && "text-cyan-400")}
                >
                  <MessageCircle size={16} /> {post.commentCount || 0}
                </Button>
              </div>

              {expandedComments[post._id] && (
                <CommentSection postId={post._id} />
              )}
            </CardContent>
          </Card>
        ))}

        {status === "CanLoadMore" && (
          <Button 
            variant="ghost" 
            className="w-full text-gray-400 hover:text-white" 
            onClick={() => loadMore(10)}
          >
            Load More
          </Button>
        )}
        
        {status === "LoadingMore" && (
          <div className="flex justify-center py-4">
            <Loader2 className="h-6 w-6 animate-spin text-cyan-500" />
          </div>
        )}
      </div>

      {/* Create Post Dialog */}
      <Dialog open={showCreatePost} onOpenChange={setShowCreatePost}>
        <DialogContent className="bg-gray-900 border-white/10 text-white">
          <DialogHeader><DialogTitle>Create Post</DialogTitle></DialogHeader>
          <Textarea value={newPostContent} onChange={e => setNewPostContent(e.target.value)} placeholder="Share something..." className="bg-white/5 border-white/10" rows={4} />
          <DialogFooter>
            <Button onClick={handleCreatePost} disabled={loading}>{loading ? 'Posting...' : 'Post'}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Post Dialog */}
      <Dialog open={showEditPost} onOpenChange={setShowEditPost}>
        <DialogContent className="bg-gray-900 border-white/10 text-white">
          <DialogHeader><DialogTitle>Edit Post</DialogTitle></DialogHeader>
          <Textarea value={editPostContent} onChange={e => setEditPostContent(e.target.value)} placeholder="Update your post..." className="bg-white/5 border-white/10" rows={4} />
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEditPost(false)} disabled={loading}>Cancel</Button>
            <Button onClick={handleUpdatePost} disabled={loading}>{loading ? 'Saving...' : 'Save Changes'}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import React from 'react';
// import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
// import { Button } from '@/components/ui/button';
// import { Progress } from '@/components/ui/progress';
// import { Badge } from '@/components/ui/badge';
// import { Target, Trophy, Calendar, CheckCircle2, Clock } from 'lucide-react';
// import { useToast } from '@/hooks/use-toast';

export function ChallengesHub() {
  const { toast } = useToast();

  const handleJoinChallenge = async (challengeId: Id<'challenges'>) => {
    try {
      await joinChallenge({ challengeId });
      toast({
        title: 'Challenge Joined!',
        description: 'Track your progress on your gamification page.',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to join challenge',
        variant: 'destructive',
      });
    }
  };

  if (!challenges) {
    return (
      <Card className="bg-white/5 border-white/10 text-white">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Target className="h-5 w-5 text-blue-500" />
            Active Challenges
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="animate-pulse space-y-4">
            <div className="h-24 bg-white/5 rounded-lg" />
            <div className="h-24 bg-white/5 rounded-lg" />
          </div>
        </CardContent>
      </Card>
    );
  }

  const userChallengeIds = new Set(
    userChallenges?.map((uc) => uc.challengeId.toString()) || []
  );

  const activeChallenges = challenges.filter((c) => c.status === 'active');

  return (
    <Card className="bg-white/5 border-white/10 text-white">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Target className="h-5 w-5 text-blue-500" />
          Active Challenges
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {activeChallenges.length === 0 ? (
          <div className="py-10 text-center text-gray-500">
            <p>No active challenges at the moment. Check back soon!</p>
          </div>
        ) : (
          activeChallenges.map((challenge) => {
            const isJoined = userChallengeIds.has(challenge._id.toString());
            const userChallenge = userChallenges?.find(
              (uc) => uc.challengeId.toString() === challenge._id.toString()
            );
            const progress = userChallenge?.progress || 0;
            const target = challenge.target || 1;
            const progressPercent = Math.min((progress / target) * 100, 100);

            return (
              <div
                key={challenge._id}
                className="p-4 rounded-lg bg-white/5 border border-white/10 space-y-3"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-white">{challenge.title}</h3>
                      {userChallenge?.completed && (
                        <Badge variant="outline" className="bg-green-500/20 text-green-400 border-green-500/50">
                          <CheckCircle2 className="h-3 w-3 mr-1" />
                          Completed
                        </Badge>
                      )}
                    </div>
                    <p className="text-sm text-gray-400">{challenge.description}</p>
                  </div>
                  <div className="flex items-center gap-2 text-yellow-500">
                    <Trophy className="h-4 w-4" />
                    <span className="text-sm font-medium">{challenge.xpReward} XP</span>
                  </div>
                </div>

                {isJoined && (
                  <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-gray-400">
                        Progress: {progress} / {target}
                      </span>
                      <span className="text-white font-medium">
                        {progressPercent.toFixed(0)}%
                      </span>
                    </div>
                    <Progress value={progressPercent} className="h-2" />
                  </div>
                )}

                <div className="flex items-center justify-between text-xs text-gray-500">
                  <div className="flex items-center gap-1">
                    {challenge.endDate ? (
                      <>
                        <Calendar className="h-3 w-3" />
                        <span>
                          Ends {new Date(challenge.endDate).toLocaleDateString()}
                        </span>
                      </>
                    ) : (
                      <>
                        <Clock className="h-3 w-3" />
                        <span>No deadline</span>
                      </>
                    )}
                  </div>
                  {!isJoined && (
                    <Button
                      size="sm"
                      onClick={() => handleJoinChallenge(challenge._id)}
                      className="bg-blue-500 hover:bg-blue-600 text-white"
                    >
                      Join Challenge
                    </Button>
                  )}
                </div>
              </div>
            );
          })
        )}
      </CardContent>
    </Card>
  );
}

