  const [isSubmitting, setIsSubmitting] = useState(false);

  const eventOptions = [
    { id: 'registration.created', label: 'Registration Created' },
    { id: 'checkin.completed', label: 'Check-in Completed' },
    { id: 'event.cancelled', label: 'Event Cancelled' },
