                <h3 style="margin-bottom: 10px;">Billed To:</h3>
                <p style="margin: 0;"><strong>${ticket.attendeeName || user?.name || 'Customer'}</strong></p>
                <p style="margin: 0;">${ticket.attendeeEmail || user?.email || ''}</p>
              </div>
              <div style="text-align: right">
                <h3 style="margin-bottom: 10px;">Details:</h3>
                <p style="margin: 0;">Date: ${format(purchaseDate, 'PPP')}</p>
                <p style="margin: 0;">Payment: Stripe Card</p>
              </div>
            </div>

            <table class="table">
              <thead>
                <tr>
                  <th>Description</th>
                  <th>Tier</th>
                  <th style="text-align: right">Amount</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td>
                    <strong>${ticket.event?.title || 'Event Registration'}</strong><br/>
                    <small>${format(eventDate, 'PPP')}</small>
                  </td>
                  <td>${ticket.ticketTypeId || 'Standard'}</td>
                  <td style="text-align: right">$${ticket.price.toFixed(2)}</td>
                </tr>
              </tbody>
            </table>

            <div class="total">
              Total Amount: $${ticket.price.toFixed(2)}
            </div>

            <div class="footer">
              <p>Thank you for your purchase! For support, contact help@eventra.app</p>
              <p>Eventra Platform • 123 Event Street, Silicon Valley, CA</p>
            </div>
          </div>
          <script>
            window.onload = function() {
              setTimeout(() => { window.print(); window.close(); }, 500);
            }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handlePrint = (ticket: EventTicket) => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const eventDate = getTicketEventDate(ticket);
    
    printWindow.document.write(`
      <html>
        <head>
          <title>Ticket - ${ticket.event?.title}</title>
          <style>
            body { font-family: sans-serif; padding: 40px; color: #333; }
            .ticket { border: 2px solid #333; padding: 30px; border-radius: 15px; max-width: 600px; margin: 0 auto; position: relative; }
            .header { border-bottom: 1px solid #eee; padding-bottom: 20px; margin-bottom: 20px; }
            .title { font-size: 24px; font-weight: bold; margin: 0; }
            .details { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
            .label { font-size: 12px; color: #666; text-transform: uppercase; }
            .value { font-size: 16px; font-weight: 500; }
            .qr-container { text-align: center; margin-top: 30px; }
            .footer { margin-top: 30px; font-size: 10px; color: #999; text-align: center; border-top: 1px solid #eee; pt: 10px; }
            @media print { .no-print { display: none; } }
          </style>
        </head>
        <body>
          <div class="ticket">
            <div class="header">
              <div class="label">Event Ticket</div>
              <h1 class="title">${ticket.event?.title}</h1>
            </div>
            <div class="details">
              <div>
                <div class="label">Attendee</div>
                <div class="value">${ticket.attendeeName || user?.name || 'Guest'}</div>
              </div>
              <div>
                <div class="label">Date</div>
                <div class="value">${format(eventDate, 'PPP')}</div>
              </div>
              <div>
                <div class="label">Ticket Number</div>
                <div class="value">${ticket.ticketNumber}</div>
              </div>
              <div>
                <div class="label">Status</div>
                <div class="value">${ticket.status}</div>
              </div>
            </div>
            <div class="qr-container">
              <div id="qrcode"></div>
              <p class="value">${ticket.ticketNumber}</p>
            </div>
            <div class="footer">
              Generated by Eventra Platform • Verified Ticket
            </div>
          </div>
          <script src="https://cdn.jsdelivr.net/npm/qrcode-generator@1.4.4/qrcode.min.js"></script>
          <script>
            window.onload = function() {
              var typeNumber = 4;
              var errorCorrectionLevel = 'L';
              var qr = qrcode(typeNumber, errorCorrectionLevel);
              qr.addData('${ticket.ticketNumber}');
              qr.make();
              document.getElementById('qrcode').innerHTML = qr.createImgTag(5);
              setTimeout(() => { window.print(); window.close(); }, 500);
            }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const filterTickets = (tab: string) => {
    return tickets.filter(ticket => {
      const eventDate = getTicketEventDate(ticket);
      if (tab === 'upcoming') return !isPast(eventDate) || isToday(eventDate);
      return isPast(eventDate) && !isToday(eventDate);
    });
  };

  if (!user && !loading) return <div className="p-20 text-center text-white"><Link href="/login" className="text-cyan-400 underline">Sign in</Link> to see your tickets</div>;

  return (
    <div className="container py-8 space-y-8 text-white">
      <h1 className="text-3xl font-bold">My Tickets</h1>
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="bg-white/5 border-white/10 text-white">
          <TabsTrigger value="upcoming">Upcoming</TabsTrigger>
          <TabsTrigger value="past">Past</TabsTrigger>
        </TabsList>
        <TabsContent value="upcoming" className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filterTickets('upcoming').map(t => <TicketCard key={t.id} ticket={t} onViewTicket={setSelectedTicket} onPrint={handlePrint} onCancel={handleCancel} onDownloadInvoice={handleDownloadInvoice} />)}
        </TabsContent>
        <TabsContent value="past" className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filterTickets('past').map(t => <TicketCard key={t.id} ticket={t} onViewTicket={setSelectedTicket} onPrint={handlePrint} onCancel={handleCancel} onDownloadInvoice={handleDownloadInvoice} />)}
        </TabsContent>
      </Tabs>

      <Dialog open={!!selectedTicket} onOpenChange={() => setSelectedTicket(null)}>
        <DialogContent className="bg-gray-900 text-white border-white/10">
          <DialogHeader><DialogTitle className="text-center">Your Ticket</DialogTitle></DialogHeader>
          <div className="flex flex-col items-center py-6">
            <div className="bg-white p-4 rounded-xl mb-4"><QRCodeSVG value={selectedTicket?.ticketNumber || ''} size={200} /></div>
            <p className="font-mono text-lg mb-6">{selectedTicket?.ticketNumber}</p>
            <Button className="w-full bg-white text-black hover:bg-gray-200" onClick={() => selectedTicket && handlePrint(selectedTicket)}>
              <Download className="mr-2 h-4 w-4" /> Download PDF Ticket
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
// import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
// import { Button } from '@/components/ui/button';
// import { Badge } from '@/components/ui/badge';
// import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
// import { Ticket, ShoppingCart, Calendar, MapPin, Loader2, QrCode, CheckCircle2 } from 'lucide-react';
// import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';
import { cn } from '@/core/utils/utils';
import Link from 'next/link';

export function TicketingClient() {
  const { user } = useAuth();
  const { toast } = useToast();
  const userId = user?._id || user?.id;
//   
  
  const [activeTab, setActiveTab] = useState('explore');
  const [bookingId, setBookingId] = useState<string | null>(null);

  const handleBook = async (eventId: string) => {
    if (!user) {
      toast({ title: "Please sign in", description: "You need an account to book tickets." });
      return;
    }
    
    setBookingId(eventId);
    try {
      await registerMutation({ eventId: eventId as any });
      toast({ title: "Booking Successful! 🎉", description: "Your ticket has been generated." });
      setActiveTab('my-tickets');
    } catch (error) {
      toast({ title: "Booking Failed", variant: "destructive" });
    } finally {
      setBookingId(null);
    }
  };

  return (
    <div className="container mx-auto p-6 space-y-6 text-white">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold">Event Tickets</h1>
          <p className="text-gray-400">Discover and book tickets for amazing events</p>
        </div>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
        <TabsList className="bg-white/5 border-white/10 text-white">
          <TabsTrigger value="explore" className="gap-2">Explore Events</TabsTrigger>
          <TabsTrigger value="my-tickets" className="gap-2">My Tickets ({myTicketsRaw.length})</TabsTrigger>
        </TabsList>
        
        <TabsContent value="explore" className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {events.filter((e: any) => e.status === 'published').map((event: any) => (
            <Card key={event._id} className="bg-white/5 border-white/10 text-white overflow-hidden flex flex-col">
              <div className="h-40 bg-gradient-to-br from-cyan-900/40 to-purple-900/40 relative">
                <Badge className="absolute top-2 right-2">{event.category}</Badge>
              </div>
              <CardHeader>
                <CardTitle className="text-xl line-clamp-1">{event.title}</CardTitle>
                <CardDescription className="text-gray-400 line-clamp-2">{event.description}</CardDescription>
              </CardHeader>
              <CardContent className="flex-1 space-y-4">
                <div className="space-y-2 text-sm text-gray-400">
                  <div className="flex items-center gap-2"><Calendar size={14} className="text-cyan-400" /> {format(event.startDate, 'PPP')}</div>
                  <div className="flex items-center gap-2"><MapPin size={14} className="text-cyan-400" /> {event.location?.venue || 'TBD'}</div>
                </div>
                <div className="pt-4 border-t border-white/10 flex items-center justify-between">
                  <p className="text-2xl font-bold text-cyan-400">{event.isPaid ? `$${event.price}` : 'FREE'}</p>
                  <Button onClick={() => handleBook(event._id)} disabled={bookingId === event._id}>
                    {bookingId === event._id ? <Loader2 className="animate-spin" /> : <ShoppingCart className="mr-2" size={16} />}
                    Book Now
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
          {events.length === 0 && <div className="col-span-full py-20 text-center text-gray-500 italic">No events available for booking yet.</div>}
        </TabsContent>
        
        <TabsContent value="my-tickets" className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {myTicketsRaw.map((ticket: any) => (
            <Card key={ticket._id} className="bg-white/5 border-white/10 text-white overflow-hidden relative">
              <div className="absolute top-0 left-0 w-1 h-full bg-cyan-500" />
              <CardHeader className="pb-2">
                <div className="flex justify-between items-start">
                  <Badge variant="outline" className="border-cyan-500/50 text-cyan-400 text-[10px]">{ticket.ticketNumber}</Badge>
                  <Badge className={cn(ticket.status === 'confirmed' ? "bg-green-500/20 text-green-400" : "bg-yellow-500/20 text-yellow-400")}>{ticket.status}</Badge>
                </div>
                <CardTitle className="text-lg mt-2">Event Ticket</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="p-4 bg-white rounded-lg flex justify-center"><QrCode size={120} className="text-black" /></div>
                <div className="text-center">
                  <p className="text-[10px] text-gray-500 uppercase">Purchase Date</p>
                  <p className="text-sm font-medium">{format(ticket.purchaseDate, 'PPP')}</p>
                </div>
                <Button variant="outline" className="w-full border-white/10" asChild>
                  <Link href={`/tickets`}><Ticket className="mr-2" size={16} /> View in Wallet</Link>
                </Button>
              </CardContent>
            </Card>
          ))}
          {myTicketsRaw.length === 0 && (
            <div className="col-span-full py-20 text-center text-gray-500 border border-dashed border-white/10 rounded-lg">
              <Ticket size={48} className="mx-auto mb-4 opacity-20" />
              <p>You haven&apos;t booked any tickets yet.</p>
              <Button variant="link" onClick={() => setActiveTab('explore')} className="text-cyan-400 mt-2">Browse Events</Button>
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}
